import {
  HomeNodeVoiceSessionCompletedSchema,
  HomeNodeVoiceSessionFailedSchema,
  HomeNodeVoiceSessionStartedSchema,
  HouseholdVoiceCaptureCreatedSchema,
  type HomeNodeVoiceSessionCompleted,
  type HomeNodeVoiceSessionFailed,
  type HomeNodeVoiceSessionStarted,
  type HouseholdVoiceCaptureCreated,
} from '@lifeos/contracts';
import { Topics, type BaseEvent, type ManagedEventBus } from '@lifeos/event-bus';
import type { AudioTranscriptionAdapter } from '@lifeos/voice-core';

const DEFAULT_SESSION_TTL_MS = 60_000;

export type VoiceSessionFailureReason =
  | 'quiet_hours'
  | 'transcription_failed'
  | 'empty_transcript'
  | 'expired';

export type VoiceSessionStatus = 'started' | 'completed' | 'failed' | 'closed';

export interface VoiceSessionRecord {
  sessionId: string;
  householdId: string;
  surfaceId: string;
  actorUserId: string;
  createdAt: string;
  updatedAt: string;
  expiresAt: string;
  status: VoiceSessionStatus;
  transcript?: string;
  targetHint?: HouseholdVoiceCaptureCreated['targetHint'];
  captureId?: string;
  audioRef?: string | null;
  failureReason?: VoiceSessionFailureReason;
  failureDetail?: string;
}

export interface VoiceSessionManagerOptions {
  eventBus: ManagedEventBus;
  transcriptionAdapter: AudioTranscriptionAdapter;
  now?: () => Date;
  idFactory?: () => string;
  sessionTtlMs?: number;
  retainAudio?: boolean;
}

export interface StartVoiceSessionInput {
  householdId: string;
  surfaceId: string;
  actorUserId: string;
  audioBuffer: Buffer;
  quietHoursActive: boolean;
}

export type StartVoiceSessionResult =
  | {
      status: 'completed';
      session: VoiceSessionRecord;
      capture: HouseholdVoiceCaptureCreated;
    }
  | {
      status: 'failed';
      session: VoiceSessionRecord;
      reason: VoiceSessionFailureReason;
    };

function cloneSession(session: VoiceSessionRecord): VoiceSessionRecord {
  return { ...session };
}

function isSessionActive(status: VoiceSessionStatus): boolean {
  return status === 'started';
}

function deriveTargetHint(text: string): HouseholdVoiceCaptureCreated['targetHint'] {
  const normalized = text.trim().toLowerCase();
  if (!normalized) {
    return 'unknown';
  }

  if (/(\bshopping\b|\bbuy\b|\bpick up\b|\bgrocer(?:y|ies)\b|\bstore\b)/.test(normalized)) {
    return 'shopping';
  }

  if (/(\bchore\b|\bclean\b|\btidy\b|\bvacuum\b|\bdishes\b|\blaundry\b)/.test(normalized)) {
    return 'chore';
  }

  if (/(\bremind\b|\breminder\b|\bremember\b|\bdon't forget\b|\bdont forget\b)/.test(normalized)) {
    return 'reminder';
  }

  if (/(\bnote\b|\bjot\b|\bwrite down\b|\bcapture\b)/.test(normalized)) {
    return 'note';
  }

  return 'unknown';
}

export class VoiceSessionManager {
  private readonly sessions = new Map<string, VoiceSessionRecord>();
  private readonly retainedAudio = new Map<string, Buffer>();
  private readonly eventBus: ManagedEventBus;
  private readonly transcriptionAdapter: AudioTranscriptionAdapter;
  private readonly now: () => Date;
  private readonly idFactory: () => string;
  private readonly sessionTtlMs: number;
  private readonly retainAudio: boolean;

  constructor(options: VoiceSessionManagerOptions) {
    this.eventBus = options.eventBus;
    this.transcriptionAdapter = options.transcriptionAdapter;
    this.now = options.now ?? (() => new Date());
    this.idFactory = options.idFactory ?? randomUUID;
    this.sessionTtlMs = options.sessionTtlMs ?? DEFAULT_SESSION_TTL_MS;
    this.retainAudio = options.retainAudio ?? false;
  }

  getSession(sessionId: string): VoiceSessionRecord | null {
    const session = this.sessions.get(sessionId);
    return session ? cloneSession(session) : null;
  }

  listSessions(): VoiceSessionRecord[] {
    return [...this.sessions.values()].map((session) => cloneSession(session));
  }

  async startSession(input: StartVoiceSessionInput): Promise<StartVoiceSessionResult> {
    const createdAt = this.now().toISOString();
    const sessionId = this.idFactory();
    const session: VoiceSessionRecord = {
      sessionId,
      householdId: input.householdId,
      surfaceId: input.surfaceId,
      actorUserId: input.actorUserId,
      createdAt,
      updatedAt: createdAt,
      expiresAt: new Date(new Date(createdAt).getTime() + this.sessionTtlMs).toISOString(),
      status: 'started',
    };
    this.sessions.set(sessionId, session);

    await this.publishStarted(session);

    if (input.quietHoursActive) {
      const failedSession = await this.markFailed(
        session,
        'quiet_hours',
        'Voice capture blocked during quiet hours.',
      );
      return { status: 'failed', session: failedSession, reason: 'quiet_hours' };
    }

    try {
      const transcript = (await this.transcriptionAdapter.transcribe(input.audioBuffer)).trim();

      // Session may have been expired while transcription was in flight.
      if (!isSessionActive(session.status)) {
        return {
          status: 'failed',
          session: cloneSession(session),
          reason: session.failureReason ?? 'expired',
        };
      }

      if (!transcript) {
        const failedSession = await this.markFailed(
          session,
          'empty_transcript',
          'Whisper produced an empty transcript.',
        );
        return { status: 'failed', session: failedSession, reason: 'empty_transcript' };
      }

      const audioRef = this.retainAudio ? this.retainSessionAudio(session.sessionId, input.audioBuffer) : null;
      const targetHint = deriveTargetHint(transcript);
      const capture = HouseholdVoiceCaptureCreatedSchema.parse({
        captureId: this.idFactory(),
        householdId: input.householdId,
        actorUserId: input.actorUserId,
        text: transcript,
        audioRef,
        source: 'ha_satellite',
        sourceDeviceId: input.surfaceId,
        targetHint,
        createdAt: this.now().toISOString(),
      });

      await this.eventBus.publish(
        Topics.lifeos.householdVoiceCaptureCreated,
        this.createEvent(
          Topics.lifeos.householdVoiceCaptureCreated,
          capture,
          input.householdId,
          input.surfaceId,
        ),
      );

      session.status = 'completed';
      session.updatedAt = this.now().toISOString();
      session.transcript = transcript;
      session.targetHint = targetHint;
      session.captureId = capture.captureId;
      session.audioRef = capture.audioRef;

      await this.publishCompleted(session, capture);
      return { status: 'completed', session: cloneSession(session), capture };
    } catch (error) {
      if (!isSessionActive(session.status)) {
        return {
          status: 'failed',
          session: cloneSession(session),
          reason: session.failureReason ?? 'expired',
        };
      }

      const failedSession = await this.markFailed(
        session,
        'transcription_failed',
        error instanceof Error ? error.message : 'Voice transcription failed.',
      );
      return { status: 'failed', session: failedSession, reason: 'transcription_failed' };
    }
  }

  async expireSessions(now: Date = this.now()): Promise<string[]> {
    const expiredIds: string[] = [];
    for (const session of this.sessions.values()) {
      if (!isSessionActive(session.status)) {
        continue;
      }

      if (new Date(session.expiresAt).getTime() > now.getTime()) {
        continue;
      }

      await this.markFailed(session, 'expired', 'Voice session expired before completion.');
      expiredIds.push(session.sessionId);
    }

    return expiredIds;
  }

  closeSession(sessionId: string): VoiceSessionRecord | null {
    const session = this.sessions.get(sessionId);
    if (!session) {
      return null;
    }

    session.status = 'closed';
    session.updatedAt = this.now().toISOString();
    this.retainedAudio.delete(sessionId);
    return cloneSession(session);
  }

  private retainSessionAudio(sessionId: string, audioBuffer: Buffer): string {
    this.retainedAudio.set(sessionId, Buffer.from(audioBuffer));
    return `memory://home-node-voice/${sessionId}`;
  }

  private async publishStarted(session: VoiceSessionRecord): Promise<void> {
    const payload: HomeNodeVoiceSessionStarted = HomeNodeVoiceSessionStartedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      started_at: session.createdAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionStarted,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionStarted,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );
  }

  private async publishCompleted(
    session: VoiceSessionRecord,
    capture: HouseholdVoiceCaptureCreated,
  ): Promise<void> {
    const payload: HomeNodeVoiceSessionCompleted = HomeNodeVoiceSessionCompletedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      capture_id: capture.captureId,
      transcript: capture.text,
      target_hint: capture.targetHint,
      completed_at: session.updatedAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionCompleted,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionCompleted,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );
  }

  private async markFailed(
    session: VoiceSessionRecord,
    reason: VoiceSessionFailureReason,
    detail: string,
  ): Promise<VoiceSessionRecord> {
    session.status = 'failed';
    session.updatedAt = this.now().toISOString();
    session.failureReason = reason;
    session.failureDetail = detail;

    const payload: HomeNodeVoiceSessionFailed = HomeNodeVoiceSessionFailedSchema.parse({
      session_id: session.sessionId,
      household_id: session.householdId,
      surface_id: session.surfaceId,
      reason,
      detail,
      failed_at: session.updatedAt,
    });
    await this.eventBus.publish(
      Topics.lifeos.homeNodeVoiceSessionFailed,
      this.createEvent(
        Topics.lifeos.homeNodeVoiceSessionFailed,
        payload,
        session.householdId,
        session.surfaceId,
      ),
    );

    return cloneSession(session);
  }

  private createEvent<T>(type: string, data: T, householdId: string, actorId: string): BaseEvent<T> {
    return {
      id: this.idFactory(),
      type,
      timestamp: this.now().toISOString(),
      source: 'home-node-voice-session-manager',
      version: '1',
      data,
      metadata: {
        household_id: householdId,
        actor_id: actorId,
        trace_id: this.idFactory(),
      },
    };
  }
}

import { randomUUID } from 'node:crypto';

import {
  HomeNodeDisplayFeedEventSchema,
  HomeNodeStateSnapshotUpdatedSchema,
  HouseholdHomeStateChangedSchema,
  HouseholdVoiceCaptureCreatedSchema,
  type HomeNodeSurfaceRegistered,
  type HomeStateSnapshot,
  type HomeNodeStateSnapshotUpdated,
} from '@lifeos/contracts';
import { createEventBusClient, Topics, type BaseEvent, type ManagedEventBus } from '@lifeos/event-bus';
import { HomeNodeGraphClient, VoiceSessionManager, buildNextSnapshot } from '@lifeos/home-node-core';
import { createEnvSecretStore, startService } from '@lifeos/service-runtime';
import { WhisperSttAdapter, type WhisperHealthSnapshot, type WhisperHealthStatus } from '@lifeos/voice-core';

import { registerHomeNodeRoutes } from './routes';

const WATCHDOG_INTERVAL_MS = 60_000;
const SURFACE_INACTIVITY_THRESHOLD_MS = 300_000;

type WatchdogStatus = 'healthy' | 'degraded';

type DisplayFeedSignalWaiter = {
  resolve: (signalVersion: number) => void;
  timeout: NodeJS.Timeout;
};

let graphClient: HomeNodeGraphClient | null = null;
let eventBus: ManagedEventBus | null = null;
let watchdogInterval: NodeJS.Timeout | null = null;
let watchdogRunning = false;
let voiceRuntimeClient: WhisperSttAdapter | null = null;
let voiceSessionManager: VoiceSessionManager | null = null;
const displayFeedSignalVersions = new Map<string, number>();
const displayFeedSignalWaiters = new Map<string, Set<DisplayFeedSignalWaiter>>();

export function getHomeNodeVoiceSessionManager(): VoiceSessionManager | null {
  return voiceSessionManager;
}

function getDisplayFeedSignalVersion(householdId: string): number {
  return displayFeedSignalVersions.get(householdId) ?? 0;
}

function signalDisplayFeedUpdated(householdId: string): number {
  const next = getDisplayFeedSignalVersion(householdId) + 1;
  displayFeedSignalVersions.set(householdId, next);

  const waiters = displayFeedSignalWaiters.get(householdId);
  if (waiters) {
    for (const waiter of waiters) {
      clearTimeout(waiter.timeout);
      waiter.resolve(next);
    }
    displayFeedSignalWaiters.delete(householdId);
  }

  return next;
}

function waitForDisplayFeedSignal(
  householdId: string,
  since: number,
  timeoutMs: number,
): Promise<number> {
  const current = getDisplayFeedSignalVersion(householdId);
  if (current > since) {
    return Promise.resolve(current);
  }

  return new Promise((resolve) => {
    const waiters = displayFeedSignalWaiters.get(householdId) ?? new Set<DisplayFeedSignalWaiter>();
    const waiter: DisplayFeedSignalWaiter = {
      resolve,
      timeout: setTimeout(() => {
        waiters.delete(waiter);
        if (waiters.size === 0) {
          displayFeedSignalWaiters.delete(householdId);
        }

        resolve(getDisplayFeedSignalVersion(householdId));
      }, timeoutMs),
    };

    waiters.add(waiter);
    displayFeedSignalWaiters.set(householdId, waiters);
  });
}

function defaultSnapshot(now: string): HomeStateSnapshot {
  return {
    home_mode: 'home',
    occupancy_summary: 'unknown',
    active_routines: [],
    adapter_health: 'healthy',
    snapshot_at: now,
  };
}

function createEvent<T>(type: string, data: T, householdId: string): BaseEvent<T> {
  return {
    id: randomUUID(),
    type,
    timestamp: new Date().toISOString(),
    source: 'home-node-service',
    version: '1',
    data,
    metadata: {
      household_id: householdId,
      trace_id: randomUUID(),
    },
  };
}

export async function publishSnapshotUpdatedEvent(
  activeGraphClient: HomeNodeGraphClient,
  activeEventBus: ManagedEventBus,
  householdId: string,
  snapshot: HomeStateSnapshot,
): Promise<void> {
  const home = activeGraphClient.getHomeByHouseholdId(householdId);
  if (!home) {
    console.warn(
      JSON.stringify({
        message: 'home-node: no home registered for household, skipping snapshot event',
        householdId,
      }),
    );
    return;
  }

  const data: HomeNodeStateSnapshotUpdated = HomeNodeStateSnapshotUpdatedSchema.parse({
    home_id: home.home_id,
    household_id: householdId,
    snapshot,
    updated_at: new Date().toISOString(),
  });

  await activeEventBus.publish(
    Topics.lifeos.homeNodeStateSnapshotUpdated,
    createEvent(Topics.lifeos.homeNodeStateSnapshotUpdated, data, householdId),
  );
}

export async function publishDisplayFeedUpdatedEvent(
  activeGraphClient: HomeNodeGraphClient,
  activeEventBus: ManagedEventBus,
  householdId: string,
  homeMode: HomeStateSnapshot['home_mode'],
): Promise<void> {
  const home = activeGraphClient.getHomeByHouseholdId(householdId);
  if (!home) {
    console.warn(
      JSON.stringify({
        message: 'home-node: no home registered for household, skipping snapshot event',
        householdId,
      }),
    );
    return;
  }

  const data = HomeNodeDisplayFeedEventSchema.parse({
    household_id: householdId,
    home_id: home.home_id,
    home_mode: homeMode,
    updated_at: new Date().toISOString(),
  });

  await activeEventBus.publish(
    Topics.lifeos.homeNodeDisplayFeedUpdated,
    createEvent(Topics.lifeos.homeNodeDisplayFeedUpdated, data, householdId),
  );
}

export async function publishSurfaceRegisteredEvent(
  activeEventBus: ManagedEventBus,
  surface: HomeNodeSurfaceRegistered,
): Promise<void> {
  await activeEventBus.publish(
    Topics.lifeos.homeNodeSurfaceRegistered,
    createEvent(Topics.lifeos.homeNodeSurfaceRegistered, surface, surface.household_id),
  );
}

export async function publishSurfaceDeregisteredEvent(
  activeEventBus: ManagedEventBus,
  surface: HomeNodeSurfaceRegistered,
): Promise<void> {
  const data = {
    ...surface,
    deregistered_at: new Date().toISOString(),
  };

  await activeEventBus.publish(
    Topics.lifeos.homeNodeSurfaceDeregistered,
    createEvent(Topics.lifeos.homeNodeSurfaceDeregistered, data, surface.household_id),
  );
}

export async function handleHomeStateChangedEvent(
  activeGraphClient: HomeNodeGraphClient,
  activeEventBus: ManagedEventBus,
  incomingEvent: BaseEvent<unknown>,
): Promise<void> {
  const payload = HouseholdHomeStateChangedSchema.parse(incomingEvent.data);
  if (!payload.consentVerified) {
    console.info(
      JSON.stringify({
        message: 'home-node skipped home-mode transition because consent is not verified',
        householdId: payload.householdId,
        stateKey: payload.stateKey,
        reason: 'consent_not_verified',
      }),
    );
    activeGraphClient.appendAmbientAction({
      householdId: payload.householdId,
      triggerType: 'home_state_changed',
      triggerRef: payload.stateKey,
      decisionSource: 'deterministic-rule-engine',
      result: 'consent_skip',
    });
    return;
  }

  const now = new Date().toISOString();
  const current = activeGraphClient.getHomeStateSnapshot(payload.householdId) ?? defaultSnapshot(now);
  const next = buildNextSnapshot(current, payload, now);

  const persisted = activeGraphClient.upsertHomeStateSnapshot({
    householdId: payload.householdId,
    homeMode: next.home_mode,
    occupancySummary: next.occupancy_summary,
    activeRoutines: next.active_routines,
    adapterHealth: next.adapter_health,
    snapshotAt: next.snapshot_at,
  });

  activeGraphClient.appendAmbientAction({
    householdId: payload.householdId,
    triggerType: 'home_state_changed',
    triggerRef: payload.stateKey,
    decisionSource: 'deterministic-rule-engine',
    result: 'accepted',
  });

  await publishSnapshotUpdatedEvent(activeGraphClient, activeEventBus, payload.householdId, persisted);

  if (current.home_mode !== persisted.home_mode) {
    await publishDisplayFeedUpdatedEvent(
      activeGraphClient,
      activeEventBus,
      payload.householdId,
      persisted.home_mode,
    );
  }
}

export function handleVoiceCaptureEvent(
  activeGraphClient: HomeNodeGraphClient,
  incomingEvent: BaseEvent<unknown>,
): void {
  const payload = HouseholdVoiceCaptureCreatedSchema.parse(incomingEvent.data);
  activeGraphClient.appendAmbientAction({
    householdId: payload.householdId,
    triggerType: 'voice_capture_created',
    triggerRef: payload.captureId,
    decisionSource: 'event_bridge',
    affectedUserIds: [payload.actorUserId],
    result: 'observed',
  });
}

function createHealthChangedPayload(
  status: 'healthy' | 'degraded',
  reason: string,
  checkedAt: string,
  details: Record<string, unknown> = {},
): Record<string, unknown> {
  return {
    status,
    reason,
    checked_at: checkedAt,
    ...details,
  };
}

export async function runVoiceRuntimeHealthWatchdog(
  activeVoiceRuntimeClient: Pick<WhisperSttAdapter, 'isConfigured' | 'checkHealth'>,
  activeEventBus: ManagedEventBus,
  previousStatus: WhisperHealthStatus | null,
): Promise<WhisperHealthStatus | null> {
  if (!activeVoiceRuntimeClient.isConfigured()) {
    return previousStatus;
  }

  const snapshot = await activeVoiceRuntimeClient.checkHealth();
  if (previousStatus !== null && snapshot.status !== previousStatus) {
    await activeEventBus.publish(
      Topics.lifeos.homeNodeHealthChanged,
      createEvent(
        Topics.lifeos.homeNodeHealthChanged,
        createHealthChangedPayload(
          snapshot.status === 'healthy' ? 'healthy' : 'degraded',
          snapshot.reason ??
            (snapshot.status === 'healthy'
              ? 'voice runtime recovered'
              : 'voice runtime health degraded'),
          snapshot.checkedAt,
          buildVoiceHealthDetails(snapshot),
        ),
        'system',
      ),
    );
  }

  return snapshot.status;
}

function buildVoiceHealthDetails(snapshot: WhisperHealthSnapshot): Record<string, unknown> {
  const details: Record<string, unknown> = {
    component: 'voice_runtime',
    runtime_status: snapshot.status,
  };

  if (snapshot.latencyMs !== undefined) {
    details.latency_ms = snapshot.latencyMs;
  }

  return details;
}

export async function runSurfaceHealthWatchdog(
  activeGraphClient: HomeNodeGraphClient,
  activeEventBus: ManagedEventBus,
  now: Date = new Date(),
): Promise<string[]> {
  const cutoff = new Date(now.getTime() - SURFACE_INACTIVITY_THRESHOLD_MS).toISOString();
  const staleSurfaces = activeGraphClient.listStaleActiveSurfaces(cutoff);

  const transitionedByHousehold = new Map<string, string[]>();
  for (const surface of staleSurfaces) {
    if (!activeGraphClient.markSurfaceInactive(surface.surface_id)) {
      continue;
    }

    const current = transitionedByHousehold.get(surface.household_id) ?? [];
    current.push(surface.surface_id);
    transitionedByHousehold.set(surface.household_id, current);
  }

  if (transitionedByHousehold.size === 0) {
    return [];
  }

  const transitionedSurfaceIds: string[] = [];
  for (const [householdId, surfaceIds] of transitionedByHousehold.entries()) {
    transitionedSurfaceIds.push(...surfaceIds);
    const data = {
      status: 'degraded',
      reason: 'stale surface heartbeats',
      checked_at: now.toISOString(),
      affected_surface_ids: surfaceIds,
    };

    await activeEventBus.publish(
      Topics.lifeos.homeNodeHealthChanged,
      createEvent(Topics.lifeos.homeNodeHealthChanged, data, householdId),
    );
  }

  return transitionedSurfaceIds;
}

/**
 * Runs one watchdog tick body under the module-level overlap guard.
 * Returns `true` when the body was executed (even if it threw), `false` when
 * skipped because a previous invocation was still in-flight.
 * Exported for unit testing of the guard and finally-reset behaviour.
 */
export async function runGuardedWatchdogTick(body: () => Promise<void>): Promise<boolean> {
  if (watchdogRunning) return false;
  watchdogRunning = true;
  try {
    await body();
  } catch (error) {
    console.error(
      JSON.stringify({
        message: 'home-node watchdog loop failed',
        error: error instanceof Error ? error.message : 'unknown_error',
      }),
    );
  } finally {
    watchdogRunning = false;
  }
  return true;
}

export async function startHomeNodeService(): Promise<void> {
  await startService({
    serviceName: 'home-node',
    enforceRouteAuthMode: 'mutating',
    port: Number(process.env.LIFEOS_HOME_NODE_PORT ?? 3010),
    secretRefs: [],
    secretStore: createEnvSecretStore(),
    healthChecks: [
      {
        name: 'home-node-db',
        check: async () => {
          if (!graphClient) {
            return { status: 'unhealthy' as const, reason: 'home-node graph not initialized' };
          }

          return graphClient.isHealthy()
            ? { status: 'healthy' as const }
            : { status: 'unhealthy' as const, reason: 'home-node graph unavailable' };
        },
      },
      {
        name: 'home-node-event-bus',
        check: async () => {
          if (!eventBus) {
            return { status: 'unhealthy' as const, reason: 'event bus not initialized' };
          }

          const health = eventBus.getConnectionHealth();
          if (health === 'connected') {
            return { status: 'healthy' as const };
          }

          if (health === 'degraded') {
            return {
              status: 'degraded' as const,
              reason: 'event bus connection is degraded',
            };
          }

          return { status: 'unhealthy' as const, reason: 'event bus is disconnected' };
        },
      },
      {
        name: 'home-node-voice-runtime',
        check: async () => {
          if (!voiceRuntimeClient?.isConfigured()) {
            return { status: 'healthy' as const };
          }

          const snapshot = await voiceRuntimeClient.checkHealth();
          if (snapshot.status === 'healthy') {
            return { status: 'healthy' as const };
          }

          if (snapshot.status === 'degraded') {
            return {
              status: 'degraded' as const,
              reason: snapshot.reason ?? 'voice runtime health degraded',
            };
          }

          return {
            status: 'unhealthy' as const,
            reason: snapshot.reason ?? 'voice runtime unavailable',
          };
        },
      },
    ],
    registerRoutes: async (app) => {
      graphClient = new HomeNodeGraphClient(
        process.env.LIFEOS_HOME_NODE_DB_PATH ?? './data/home-node.db',
      );
      graphClient.initializeSchema();

      eventBus = createEventBusClient({
        env: process.env,
      });
      voiceRuntimeClient = new WhisperSttAdapter();
      voiceSessionManager = new VoiceSessionManager({
        eventBus,
        transcriptionAdapter: voiceRuntimeClient,
        sessionTtlMs: process.env.LIFEOS_HOME_NODE_VOICE_SESSION_TTL_MS
          ? Number(process.env.LIFEOS_HOME_NODE_VOICE_SESSION_TTL_MS)
          : undefined,
        retainAudio:
          process.env.LIFEOS_HOME_NODE_VOICE_RETAIN_AUDIO?.trim().toLowerCase() === 'true',
      });

      await eventBus.subscribe(Topics.lifeos.householdHomeStateChanged, async (event) => {
        await handleHomeStateChangedEvent(graphClient as HomeNodeGraphClient, eventBus as ManagedEventBus, event as BaseEvent<unknown>);
      });

      await eventBus.subscribe(Topics.lifeos.householdVoiceCaptureCreated, async (event) => {
        handleVoiceCaptureEvent(graphClient as HomeNodeGraphClient, event as BaseEvent<unknown>);
      });

      registerHomeNodeRoutes(app, graphClient, {
        onSurfaceRegistered: async (surface) => {
          await publishSurfaceRegisteredEvent(eventBus as ManagedEventBus, surface);
        },
        onSurfaceDeregistered: async (surface) => {
          await publishSurfaceDeregisteredEvent(eventBus as ManagedEventBus, surface);
        },
        getDisplayFeedSignalVersion,
        waitForDisplayFeedSignal,
      });

      await eventBus.subscribe(Topics.lifeos.homeNodeDisplayFeedUpdated, async (event) => {
        const payload = HomeNodeDisplayFeedEventSchema.parse(event.data);
        signalDisplayFeedUpdated(payload.household_id);
      });

      let lastStatus: WatchdogStatus = 'healthy';
      let lastVoiceRuntimeStatus: WhisperHealthStatus | null = null;
      watchdogInterval = setInterval(async () => {
        if (!eventBus || !graphClient) {
          return;
        }
        await runGuardedWatchdogTick(async () => {
          const health = eventBus!.getConnectionHealth();
          const currentStatus: WatchdogStatus = health === 'connected' ? 'healthy' : 'degraded';
          if (currentStatus === 'degraded' && currentStatus !== lastStatus) {
            const data = {
              status: 'degraded',
              reason: `event bus connection ${health}`,
              checked_at: new Date().toISOString(),
            };

            await eventBus!.publish(
              Topics.lifeos.homeNodeHealthChanged,
              createEvent(Topics.lifeos.homeNodeHealthChanged, data, 'system'),
            );
          }

          await runSurfaceHealthWatchdog(graphClient!, eventBus!);
          await voiceSessionManager?.expireSessions();
          if (voiceRuntimeClient) {
            lastVoiceRuntimeStatus = await runVoiceRuntimeHealthWatchdog(
              voiceRuntimeClient,
              eventBus!,
              lastVoiceRuntimeStatus,
            );
          }
          lastStatus = currentStatus;
        });
      }, WATCHDOG_INTERVAL_MS);

      app.addHook('onClose', async () => {
        if (watchdogInterval) {
          clearInterval(watchdogInterval);
          watchdogInterval = null;
        }
        watchdogRunning = false;

        await eventBus?.close();
        voiceSessionManager = null;
        voiceRuntimeClient = null;
        for (const waiters of displayFeedSignalWaiters.values()) {
          for (const waiter of waiters) {
            clearTimeout(waiter.timeout);
          }
        }
        displayFeedSignalWaiters.clear();
        displayFeedSignalVersions.clear();
        graphClient?.close();
      });
    },
  });
}

export * from './types';

import fastify from 'fastify';

import { loadConfig, type ResolvedConfig } from '@lifeos/config';
import { HealthRegistry, livenessHandler, readinessHandler } from '@lifeos/health';
import {
  createObservabilityClient,
  type ObservabilityClient,
  type ObservabilityConfig,
} from '@lifeos/observability';
import { createPolicyClient } from '@lifeos/policy-engine';
import { createSecurityClient, type JwtPayload } from '@lifeos/security';
import { applySecretPolicy, SecretsError } from '@lifeos/secrets';
import type { SecretStore } from '@lifeos/secrets';

import type { RouteAuthMode, ServiceRuntimeOptions, ServiceRuntimePhase } from './types';

function createNoopObservabilityClient(): ObservabilityClient {
  return {
    startSpan: () => ({
      traceId: 'noop-trace',
      spanId: 'noop-span',
    }),
    endSpan: () => {
      return;
    },
    recordMetric: () => {
      return;
    },
    log: () => {
      return;
    },
  };
}

interface InternalServiceRuntimeOptions extends ServiceRuntimeOptions {
  onAuthPolicy?: (config: ResolvedConfig) => Promise<void>;
  onPhase?: (phase: ServiceRuntimePhase) => void | Promise<void>;
}

export function createEnvSecretStore(): SecretStore {
  return {
    get: async (name: string) => process.env[name] ?? null,
    set: async () => undefined,
  };
}

/**
 * Validates and normalizes the service port.
 * @throws Error if port is invalid
 */
function validatePort(port: number): number {
  if (!Number.isInteger(port) || port < 1 || port > 65535) {
    throw new Error(`Invalid port number: ${port}. Must be between 1 and 65535.`);
  }
  return port;
}

/**
 * Validates and normalizes the binding host.
 * Prevents binding to all interfaces without explicit configuration.
 * @throws Error if host is invalid
 */
function validateHost(host: string | undefined): string {
  if (!host || host.trim().length === 0) {
    // Default to localhost in development, explicit in production
    const env = process.env.NODE_ENV ?? 'development';
    return env === 'production' ? 'localhost' : '127.0.0.1';
  }

  const normalized = host.trim();

  // Warn about 0.0.0.0 binding outside production
  if (normalized === '0.0.0.0' && process.env.NODE_ENV !== 'production') {
    console.warn(
      '[service-runtime] WARNING: Binding to 0.0.0.0 outside production. Consider using localhost or an explicit IP.',
    );
  }

  // Only allow safe host patterns
  if (
    !/^(\d{1,3}\.){3}\d{1,3}$|^[a-z0-9][a-z0-9-]*[a-z0-9](\.[a-z0-9][a-z0-9-]*[a-z0-9])*$|^localhost$|^::1$|^::.?$/i.test(
      normalized,
    )
  ) {
    throw new Error(`Invalid host: ${normalized}. Must be a valid IPv4, IPv6, or hostname.`);
  }

  return normalized;
}

function terminateBoot(error: unknown, message: string): never {
  const detail = error instanceof Error ? error.message : String(error);
  console.error(`${message}: ${detail}`);
  process.exit(1);
  throw error instanceof Error ? error : new Error(detail);
}

function shouldEnforceMutatingAuth(method: string): boolean {
  return method === 'POST' || method === 'PUT' || method === 'PATCH' || method === 'DELETE';
}

function shouldEnforceAuth(method: string, path: string, mode: RouteAuthMode): boolean {
  if (mode === 'all') {
    return true;
  }

  if (mode === 'api-prefix') {
    return path.startsWith('/api/');
  }

  return shouldEnforceMutatingAuth(method);
}

type RuntimeSecurityConfig = {
  policyEnforce?: boolean;
  failClosed?: boolean;
};

function resolveAuthPolicy(
  opts: ServiceRuntimeOptions,
  configSecurity: RuntimeSecurityConfig | undefined,
): { mode: RouteAuthMode; enabled: boolean } {
  const hasLegacyAuthFlags =
    opts.enforceMutatingRouteAuth !== undefined || opts.enableAuth !== undefined;

  if (opts.enforceRouteAuthMode !== undefined) {
    if (hasLegacyAuthFlags) {
      console.warn(
        `[service-runtime] ${opts.serviceName}: enforceRouteAuthMode is set; enableAuth and enforceMutatingRouteAuth are deprecated and ignored.`,
      );
    }

    return {
      mode: opts.enforceRouteAuthMode,
      enabled: true,
    };
  }

  if (opts.enforceMutatingRouteAuth !== undefined) {
    return {
      mode: 'mutating',
      enabled: opts.enforceMutatingRouteAuth,
    };
  }

  if (opts.enableAuth !== undefined) {
    return {
      mode: 'mutating',
      enabled: opts.enableAuth,
    };
  }

  if (configSecurity?.policyEnforce !== undefined) {
    return {
      mode: 'mutating',
      enabled: configSecurity.policyEnforce,
    };
  }

  return {
    mode: 'mutating',
    enabled: true,
  };
}

function extractBearerToken(value: string | undefined): string | null {
  if (!value) {
    return null;
  }

  const [scheme, token] = value.trim().split(/\s+/, 2);
  if (!scheme || !token || scheme.toLowerCase() !== 'bearer') {
    return null;
  }

  return token.trim() || null;
}

export async function startService(opts: InternalServiceRuntimeOptions): Promise<void> {
  // Validate input immediately
  if (!opts.serviceName || opts.serviceName.trim().length === 0) {
    terminateBoot(new Error('serviceName is required'), 'Service initialization failed');
  }

  const markPhase = async (phase: ServiceRuntimePhase): Promise<void> => {
    await opts.onPhase?.(phase);
  };

  // Track degraded secrets for health checks
  const allDegradedSecrets: Array<{ reason: string }> = [];

  let resolvedConfig: ResolvedConfig;
  await markPhase('config');
  try {
    const loaded = await loadConfig({
      secretStore: opts.secretStore,
      secretRefs: opts.secretRefs,
      isFeatureEnabled: opts.isFeatureEnabled,
    });
    resolvedConfig = loaded.config;
    for (const marker of loaded.degraded) {
      allDegradedSecrets.push({ reason: marker.reason });
    }
  } catch (error) {
    terminateBoot(error, 'Failed to load configuration');
  }

  await markPhase('secrets');
  for (const ref of opts.secretRefs ?? []) {
    const value = (await opts.secretStore?.get(ref.name)) ?? null;
    let featureEnabled: boolean | undefined;
    if (ref.policy === 'required_if_feature_enabled') {
      if (opts.isFeatureEnabled) {
        featureEnabled = await opts.isFeatureEnabled(ref.featureGate ?? '');
      } else {
        featureEnabled = (resolvedConfig.features as Record<string, boolean> | undefined)?.[
          ref.featureGate ?? ''
        ];
      }
    }
    try {
      const outcome = applySecretPolicy(ref, value, featureEnabled);
      if (typeof outcome !== 'string') {
        allDegradedSecrets.push({ reason: outcome.reason });
      }
    } catch (error) {
      if (error instanceof SecretsError) {
        terminateBoot(error, '[service-runtime] boot aborted');
      }
      throw error;
    }
  }
  if (allDegradedSecrets.length > 0) {
    console.warn(
      JSON.stringify({
        message: 'service starting with degraded secrets',
        serviceName: opts.serviceName,
        degradedSecrets: allDegradedSecrets.map((m) => m.reason),
      }),
    );
  }

  const observabilityConfig: ObservabilityConfig = opts.observabilityConfig ?? {
    serviceName: opts.serviceName,
    environment: resolvedConfig.profile ?? 'development',
  };

  await markPhase('observability');
  const createObservability =
    opts.observabilityFactory ??
    ((config: ObservabilityConfig): ObservabilityClient =>
      (createObservabilityClient as unknown as (cfg: ObservabilityConfig) => ObservabilityClient)(
        config,
      ));

  let observabilityClient: ObservabilityClient;
  try {
    observabilityClient = createObservability(observabilityConfig);
  } catch (error) {
    if (opts.allowObservabilityInitFallback === false) {
      terminateBoot(error, 'Failed to initialize observability');
    }
    const detail = error instanceof Error ? error.message : String(error);
    console.warn(
      `[service-runtime] observability initialization failed, falling back to noop: ${detail}`,
    );
    observabilityClient = createNoopObservabilityClient();
  }

  const app = fastify({ logger: true, requestTimeout: 30_000 });

  // Add security headers middleware
  app.addHook('onSend', async (request, reply) => {
    reply.header('X-Content-Type-Options', 'nosniff');
    reply.header('X-Frame-Options', 'DENY');
    if (process.env.NODE_ENV === 'production') {
      reply.header('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
    }
    reply.header('Content-Security-Policy', "default-src 'self'");
    reply.header('Referrer-Policy', 'no-referrer');
    reply.header('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');
    // Do not expose server version
    reply.header('Server', 'LifeOS');
  });

  await markPhase('auth/policy');
  const configSecurity = (
    resolvedConfig as unknown as {
      security?: RuntimeSecurityConfig;
    }
  ).security;
  const failClosed = opts.failClosed ?? configSecurity?.failClosed ?? true;
  const authPolicy = resolveAuthPolicy(opts, configSecurity);
  const securityClient = createSecurityClient();
  const policyClient = createPolicyClient();

  app.addHook('onRequest', async (request, reply) => {
    request.log.info({ serviceName: opts.serviceName }, 'service identity');

    if (request.url.startsWith('/health/')) {
      return;
    }

    if (!authPolicy.enabled || !shouldEnforceAuth(request.method, request.url, authPolicy.mode)) {
      return;
    }

    const authorization = request.headers.authorization;
    const token = extractBearerToken(
      Array.isArray(authorization) ? authorization[0] : authorization,
    );
    if (!token) {
      observabilityClient.log('warn', 'mutating request denied: missing bearer token', {
        topic: 'lifeos.security.auth.failed',
        serviceName: opts.serviceName,
        method: request.method,
        path: request.url,
      });
      reply.code(401).send({ error: 'Invalid or expired token' });
      return reply;
    }

    let payload: JwtPayload | null = null;
    try {
      payload = await securityClient.verifyJwt(token);
    } catch (error: unknown) {
      if (failClosed) {
        observabilityClient.log('error', 'mutating request denied: jwt verification failed', {
          topic: 'lifeos.security.auth.failed',
          serviceName: opts.serviceName,
          method: request.method,
          path: request.url,
          error: error instanceof Error ? error.message : String(error),
        });
        reply.code(401).send({ error: 'Invalid or expired token' });
        return reply;
      }
      return;
    }

    if (!payload) {
      observabilityClient.log('warn', 'mutating request denied: invalid token', {
        topic: 'lifeos.security.auth.failed',
        serviceName: opts.serviceName,
        method: request.method,
        path: request.url,
      });
      reply.code(401).send({ error: 'Invalid or expired token' });
      return reply;
    }

    const policyResult = await policyClient.evaluatePolicy({
      subject: payload.sub,
      action: `service.${opts.serviceName}.${request.method.toLowerCase()}`,
      resource: request.url.split('?')[0] ?? request.url,
      context: {
        serviceName: opts.serviceName,
        method: request.method,
        path: request.url,
        scopes: payload.scopes,
      },
    });

    if (!policyResult.allowed) {
      observabilityClient.log('warn', 'mutating request denied: policy rejection', {
        topic: 'lifeos.security.policy.denied',
        serviceName: opts.serviceName,
        method: request.method,
        path: request.url,
        reason: policyResult.reason,
      });
      reply.code(403).send({ error: policyResult.reason ?? 'Policy denied mutating request' });
      return reply;
    }
  });

  try {
    await opts.onAuthPolicy?.(resolvedConfig);
  } catch (error) {
    terminateBoot(error, 'Failed to initialize auth/policy');
  }

  try {
    await opts.registerPlugins?.(app);
  } catch (error) {
    terminateBoot(error, 'Failed to register plugins');
  }

  await markPhase('routes');
  try {
    const registerRoutesHandler =
      opts.registerRoutes ??
      (async () => {
        return;
      });
    await registerRoutesHandler(app);
  } catch (error) {
    terminateBoot(error, 'Failed to register routes');
  }

  await markPhase('health/readiness');
  const healthRegistry = new HealthRegistry();
  for (const healthCheck of opts.healthChecks ?? []) {
    healthRegistry.register(healthCheck);
  }
  healthRegistry.register({
    name: 'secrets',
    check: async () => {
      if (allDegradedSecrets.length === 0) {
        return { status: 'healthy' as const };
      }

      return {
        status: 'degraded' as const,
        reason: allDegradedSecrets.map((marker) => marker.reason).join('; '),
      };
    },
  });
  healthRegistry.register({
    name: 'liveness',
    check: async () => ({
      status: 'healthy' as const,
    }),
  });
  let readinessInProgress = false;
  healthRegistry.register({
    name: 'readiness',
    check: async () => {
      if (readinessInProgress) {
        return { status: 'healthy' as const };
      }

      readinessInProgress = true;
      try {
        const aggregate = await healthRegistry.runAll();
        return { status: aggregate.status as 'healthy' | 'degraded' | 'unhealthy' };
      } catch (error) {
        const reason = error instanceof Error ? error.message : 'Health check failed';
        return { status: 'unhealthy' as const, reason };
      } finally {
        readinessInProgress = false;
      }
    },
  });

  if (opts.enableLiveness !== false) {
    app.get('/health/live', async (_request, reply) => {
      try {
        const response = await livenessHandler(healthRegistry)();
        reply.code(response.status).send(response.body);
      } catch (error) {
        const detail = error instanceof Error ? error.message : 'Unknown error';
        reply.code(500).send({ error: `Liveness check failed: ${detail}` });
      }
    });
  }

  if (opts.enableReadiness !== false) {
    app.get('/health/ready', async (_request, reply) => {
      try {
        const response = await readinessHandler(healthRegistry)();
        reply.code(response.status).send(response.body);
      } catch (error) {
        const detail = error instanceof Error ? error.message : 'Unknown error';
        reply.code(500).send({ error: `Readiness check failed: ${detail}` });
      }
    });
  }

  await markPhase('listen');
  let validatedPort: number;
  let validatedHost: string;

  try {
    const rawPort = opts.port ?? Number(process.env.PORT ?? 3000);
    validatedPort = validatePort(rawPort);
  } catch (error) {
    terminateBoot(error, 'Invalid port configuration');
  }

  try {
    validatedHost = validateHost(process.env.HOST);
  } catch (error) {
    terminateBoot(error, 'Invalid host configuration');
  }

  try {
    await opts.onBeforeListen?.(app);
  } catch (error) {
    terminateBoot(error, 'Failed to initialize listen hook');
  }

  if (opts.skipListen) {
    return;
  }

  try {
    await app.listen({ port: validatedPort, host: validatedHost });
  } catch (error) {
    terminateBoot(error, 'Failed to start listening');
  }

  observabilityClient.log('info', `${opts.serviceName} listening`, {
    serviceName: opts.serviceName,
    port: validatedPort,
    host: validatedHost,
  });

  // Graceful shutdown handling
  const gracefulShutdown = async () => {
    console.log(`[service-runtime] Shutting down ${opts.serviceName} gracefully...`);
    try {
      await app.close();
      console.log(`[service-runtime] ${opts.serviceName} shutdown complete.`);
    } catch (error) {
      console.error(
        `[service-runtime] Error during shutdown: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  };

  process.on('SIGTERM', () => {
    void gracefulShutdown();
  });

  process.on('SIGINT', () => {
    void gracefulShutdown();
  });
}

import type { FastifyInstance } from 'fastify';

import type { HealthCheck } from '@lifeos/health';
import type { ObservabilityClient, ObservabilityConfig } from '@lifeos/observability';
import type { SecretRef, SecretStore } from '@lifeos/secrets';

export type ServiceRuntimePhase =
  | 'config'
  | 'secrets'
  | 'observability'
  | 'auth/policy'
  | 'routes'
  | 'health/readiness'
  | 'listen';

export type RouteAuthMode = 'mutating' | 'api-prefix' | 'all';

export interface ServiceRuntimeOptions {
  serviceName: string;
  registerRoutes?: (app: FastifyInstance) => Promise<void>;
  registerPlugins?: (app: FastifyInstance) => Promise<void>;
  configSchema?: object;
  port?: number;
  /** Legacy metadata hint for service classification. Secret enforcement is determined by SecretRef.policy (e.g., 'required' triggers fail-fast via applySecretPolicy), not by this flag. */
  isCoreService?: boolean;
  /** @deprecated Use `isCoreService` instead. Will be removed in a future release. Neither this flag nor `isCoreService` governs secret enforcement; use `SecretRef.policy` instead. */
  isCorService?: boolean;
  /** @deprecated Use `enforceRouteAuthMode` instead. Ignored when `enforceRouteAuthMode` is set. Will be removed in a future release. */
  enableAuth?: boolean;
  /** @deprecated Use `enforceRouteAuthMode` instead. Ignored when `enforceRouteAuthMode` is set. Will be removed in a future release. */
  enforceMutatingRouteAuth?: boolean;
  enforceRouteAuthMode?: RouteAuthMode;
  enableMetrics?: boolean;
  enableReadiness?: boolean;
  enableLiveness?: boolean;
  failClosed?: boolean;
  secretRefs?: SecretRef[];
  secretStore?: SecretStore;
  observabilityConfig?: ObservabilityConfig;
  observabilityFactory?: (config: ObservabilityConfig) => ObservabilityClient;
  allowObservabilityInitFallback?: boolean;
  isFeatureEnabled?: (featureGate: string) => boolean | Promise<boolean>;
  healthChecks?: HealthCheck[];
  onBeforeListen?: (app: FastifyInstance) => void | Promise<void>;
  skipListen?: boolean;
}

export type ServiceRuntime = void;

export { loadConfig } from './loader';
export { ConfigSchema } from './schema';
export { resolveSecretRefs } from './secret-refs';
export {
  ConfigError,
  type FeatureEnabledPredicate,
  type LoadConfigOptions,
  type LoadConfigResult,
  type ResolvedConfig,
  type ResolveSecretRefsResult,
  type SecretResolutionOutcome,
} from './types';

import { readFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import type { SecretStore } from '@lifeos/secrets';
import { ZodIssue } from 'zod';
import { parse } from 'yaml';

import { applyEnvOverrides } from './env-override';
import { resolveProfile } from './profile';
import { ConfigSchema } from './schema';
import { resolveSecretRefs } from './secret-refs';
import { ConfigError, type LoadConfigOptions, type LoadConfigResult } from './types';

interface NodeErrnoException extends Error {
  code?: string;
  path?: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function isErrnoException(error: unknown): error is NodeErrnoException {
  return error instanceof Error && 'code' in error;
}

async function readYamlFile(path: string, required: boolean): Promise<Record<string, unknown>> {
  try {
    // Validate path is not empty
    if (!path || path.trim().length === 0) {
      throw new ConfigError('Config file path cannot be empty');
    }

    const content = await readFile(path, 'utf8');

    // Validate content is not empty before parsing
    if (!content || content.trim().length === 0) {
      if (required) {
        throw new ConfigError(`Config file is empty: ${path}`);
      }
      return {};
    }

    let parsed: unknown;
    try {
      parsed = parse(content) as unknown;
    } catch (parseError: unknown) {
      const detail = parseError instanceof Error ? parseError.message : String(parseError);
      throw new ConfigError(`YAML parsing failed in ${path}: ${detail}`);
    }

    if (!parsed) {
      return {};
    }

    if (!isRecord(parsed)) {
      throw new ConfigError(`YAML root must be an object in ${path}.`);
    }

    return parsed;
  } catch (error) {
    if (!required && isErrnoException(error) && error.code === 'ENOENT') {
      return {};
    }

    if (isErrnoException(error)) {
      if (error.code === 'EACCES') {
        throw new ConfigError(`Permission denied reading config file: ${path}`);
      }
      if (error.code === 'EISDIR') {
        throw new ConfigError(`Config path is a directory, not a file: ${path}`);
      }
      if (error.code === 'EMFILE') {
        throw new ConfigError('Too many open files: cannot read config');
      }
    }

    if (error instanceof ConfigError) {
      throw error;
    }

    throw error;
  }
}

function deepMerge(base: unknown, override: unknown): unknown {
  if (override === null) {
    return undefined;
  }

  if (Array.isArray(override)) {
    return JSON.parse(JSON.stringify(override)) as unknown;
  }

  if (isRecord(base) && isRecord(override)) {
    const out: Record<string, unknown> = { ...base };
    for (const [key, overrideValue] of Object.entries(override)) {
      const merged = deepMerge(out[key], overrideValue);
      if (merged === undefined) {
        delete out[key];
      } else {
        out[key] = merged;
      }
    }
    return out;
  }

  return override === undefined ? base : override;
}

function formatIssuePath(path: ReadonlyArray<PropertyKey>): string {
  return path.reduce<string>((output, segment) => {
    if (typeof segment === 'number') {
      return `${output}[${segment}]`;
    }

    const key = typeof segment === 'string' ? segment : String(segment);
    return output ? `${output}.${key}` : key;
  }, '');
}

function isDegradedPathIssue(issue: ZodIssue, degradedPaths: Set<string>): boolean {
  if (!degradedPaths.has(formatIssuePath(issue.path))) {
    return false;
  }

  return issue.code === 'invalid_type';
}

export async function loadConfig(
  options: LoadConfigOptions & { secretStore?: SecretStore } = {},
): Promise<LoadConfigResult> {
  try {
    const thisFile = fileURLToPath(import.meta.url);
    const rootDir = resolve(dirname(thisFile), '../../../');
    const configDir = resolve(rootDir, 'config');

    // Validate config directory exists
    if (!configDir || configDir.trim().length === 0) {
      throw new ConfigError('Config directory path is invalid');
    }

    const defaultsPath = resolve(configDir, 'defaults.yaml');
    const localPath = resolve(configDir, 'local.yaml');

    const defaultsConfig = await readYamlFile(defaultsPath, true);
    const localConfig = await readYamlFile(localPath, false);

    const profileName = options.profile ?? resolveProfile(process.env, localConfig, defaultsConfig);

    // Validate profile name
    if (!profileName || profileName.trim().length === 0) {
      throw new ConfigError('Profile name is invalid');
    }

    // Prevent path traversal attacks
    if (profileName.includes('..') || profileName.includes('/') || profileName.includes('\\')) {
      throw new ConfigError(`Invalid profile name: ${profileName}`);
    }

    const profilePath = resolve(configDir, 'profiles', `${profileName}.yaml`);
    const profileConfig = await readYamlFile(profilePath, false);

    const merged = deepMerge(deepMerge(defaultsConfig, profileConfig), localConfig);
    if (!isRecord(merged)) {
      throw new ConfigError('Merged config must be an object.');
    }

    const withEnvOverrides = applyEnvOverrides(merged, process.env);
    const parsedBeforeSecrets = ConfigSchema.safeParse(withEnvOverrides);
    if (!parsedBeforeSecrets.success) {
      throw new ConfigError(`Invalid configuration: ${parsedBeforeSecrets.error.message}`);
    }

    const defaultIsFeatureEnabled = (gate: string): boolean => {
      const features = parsedBeforeSecrets.data.features as Record<string, unknown>;
      return features[gate] === true;
    };

    const secretResolution = options.secretStore
      ? await resolveSecretRefs(
          parsedBeforeSecrets.data,
          options.secretStore,
          options.secretRefs,
          options.isFeatureEnabled ?? defaultIsFeatureEnabled,
        )
      : {
          config: parsedBeforeSecrets.data,
          degraded: [],
          degradedPaths: [],
          secretOutcomes: [],
        };

    const parsedFinal = ConfigSchema.safeParse(secretResolution.config);
    if (!parsedFinal.success) {
      const degradedPaths = new Set(secretResolution.degradedPaths);
      const remainingIssues = parsedFinal.error.issues.filter(
        (issue) => !isDegradedPathIssue(issue, degradedPaths),
      );

      if (remainingIssues.length > 0) {
        throw new ConfigError(`Invalid resolved configuration: ${parsedFinal.error.message}`);
      }

      return {
        config: secretResolution.config as LoadConfigResult['config'],
        degraded: secretResolution.degraded,
        degradedPaths: secretResolution.degradedPaths,
        secretOutcomes: secretResolution.secretOutcomes,
      };
    }

    return {
      config: parsedFinal.data,
      degraded: secretResolution.degraded,
      degradedPaths: secretResolution.degradedPaths,
      secretOutcomes: secretResolution.secretOutcomes,
    };
  } catch (error) {
    if (error instanceof ConfigError) {
      throw error;
    }

    // Wrap unexpected errors
    throw new ConfigError(
      `Configuration loading failed: ${error instanceof Error ? error.message : String(error)}`,
    );
  }
}

import { ConfigError, LIFEOS_ENV_PREFIX } from './types';

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function parseRawValue(raw: string, template: unknown, pathText: string): unknown {
  if (typeof template === 'boolean') {
    const lowered = raw.trim().toLowerCase();
    if (lowered === 'true' || lowered === '1') {
      return true;
    }
    if (lowered === 'false' || lowered === '0') {
      return false;
    }
    throw new ConfigError(`Invalid boolean for env override '${pathText}'.`);
  }

  if (typeof template === 'number') {
    const parsed = Number(raw);
    if (!Number.isFinite(parsed)) {
      throw new ConfigError(`Invalid number for env override '${pathText}'.`);
    }
    return parsed;
  }

  if (typeof template === 'string') {
    return raw;
  }

  if (Array.isArray(template) || isRecord(template)) {
    try {
      return JSON.parse(raw) as unknown;
    } catch {
      throw new ConfigError(
        `Invalid JSON for env override '${pathText}'. Objects and arrays must be JSON encoded.`,
      );
    }
  }

  throw new ConfigError(`Unsupported env override path '${pathText}'.`);
}

function getPathValue(root: Record<string, unknown>, path: string[]): unknown {
  let cursor: unknown = root;

  for (const segment of path) {
    if (!isRecord(cursor) || !(segment in cursor)) {
      return undefined;
    }
    cursor = cursor[segment];
  }

  return cursor;
}

function setPathValue(root: Record<string, unknown>, path: string[], value: unknown): void {
  let cursor = root;

  for (let index = 0; index < path.length - 1; index += 1) {
    const key = path[index];
    if (!key) {
      throw new ConfigError('Invalid env override path segment.');
    }

    const next = cursor[key];
    if (!isRecord(next)) {
      throw new ConfigError(`Unknown env override path '${path.join('.')}'.`);
    }

    cursor = next;
  }

  const leaf = path[path.length - 1];
  if (!leaf || !(leaf in cursor)) {
    throw new ConfigError(`Unknown env override path '${path.join('.')}'.`);
  }

  cursor[leaf] = value;
}

export function applyEnvOverrides(config: object, env: Record<string, string | undefined>): object {
  const output = JSON.parse(JSON.stringify(config)) as Record<string, unknown>;

  for (const [key, raw] of Object.entries(env)) {
    if (!key.startsWith(LIFEOS_ENV_PREFIX) || raw === undefined) {
      continue;
    }

    const segments = key
      .slice(LIFEOS_ENV_PREFIX.length)
      .split('__')
      .map((segment) => segment.trim())
      .filter((segment) => segment.length > 0);

    if (segments.length === 0) {
      throw new ConfigError(`Invalid env override key '${key}'.`);
    }

    const existingValue = getPathValue(output, segments);
    if (existingValue === undefined) {
      throw new ConfigError(`Unknown env override path '${segments.join('.')}'.`);
    }

    const parsed = parseRawValue(raw, existingValue, segments.join('.'));
    setPathValue(output, segments, parsed);
  }

  return output;
}

