export interface SecretResolutionOutcome {
  name: string;
  path: string;
  status: 'resolved' | 'degraded';
  value?: string;
  marker?: DegradedMarker;
}

export interface ResolveSecretRefsResult<T extends object> {
  config: T;
  degraded: DegradedMarker[];
  degradedPaths: string[];
