export class ConfigError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ConfigError';
  }
}

export function resolveProfile(
  env: NodeJS.ProcessEnv,
  localConfig: Record<string, unknown>,
  defaultsConfig: Record<string, unknown>,
): string {
  const envProfile = env.LIFEOS_PROFILE?.trim();
  if (envProfile) {
    return envProfile;
  }

  const localProfile = localConfig.profile;
  if (typeof localProfile === 'string' && localProfile.trim().length > 0) {
    return localProfile;
  }

  const defaultsProfile = defaultsConfig.profile;
  if (typeof defaultsProfile === 'string' && defaultsProfile.trim().length > 0) {
    return defaultsProfile;
  }

  return 'assistant';
}

import { applySecretPolicy, type SecretRef, type SecretStore } from '@lifeos/secrets';

import { ConfigError, type FeatureEnabledPredicate, type ResolveSecretRefsResult } from './types';

const SECRET_REF_PATTERN = /^!secret\s+(.+)$/;

function formatPath(pathSegments: Array<string | number>): string {
  return pathSegments.reduce<string>((output, segment) => {
    if (typeof segment === 'number') {
      return `${output}[${segment}]`;
    }

    return output ? `${output}.${segment}` : segment;
  }, '');
}

export async function resolveSecretRefs<T extends object>(
  config: T,
  secretStore: SecretStore,
  secretRefs: SecretRef[] = [],
  isFeatureEnabled?: FeatureEnabledPredicate,
): Promise<ResolveSecretRefsResult<T>> {
  const degraded = [] as ResolveSecretRefsResult<T>['degraded'];
  const degradedPaths = [] as ResolveSecretRefsResult<T>['degradedPaths'];
  const secretOutcomes = [] as ResolveSecretRefsResult<T>['secretOutcomes'];
  const secretRefMap = new Map(secretRefs.map((secretRef) => [secretRef.name, secretRef]));

  async function walk(
    value: unknown,
    path: string,
    pathSegments: Array<string | number>,
  ): Promise<unknown> {
    if (typeof value === 'string') {
      const match = value.match(SECRET_REF_PATTERN);
      if (!match) {
        return value;
      }

      const secretName = match[1]?.trim();
      if (!secretName) {
        throw new ConfigError(`Invalid secret reference at ${path}.`);
      }

      const secretRef = secretRefMap.get(secretName);
      const resolved = await secretStore.get(secretName);
      if (!secretRef) {
        if (resolved === null) {
          throw new ConfigError(`Unable to resolve required secret '${secretName}' at ${path}.`);
        }
        return resolved;
      }

      const featureEnabled =
        secretRef.policy === 'required_if_feature_enabled' && secretRef.featureGate
          ? await isFeatureEnabled?.(secretRef.featureGate)
          : undefined;
      const policyOutcome = applySecretPolicy(secretRef, resolved, featureEnabled);

      if (typeof policyOutcome !== 'string') {
        degraded.push(policyOutcome);
        degradedPaths.push(formatPath(pathSegments));
        secretOutcomes.push({
          name: secretName,
          path: formatPath(pathSegments),
          status: 'degraded',
          marker: policyOutcome,
        });
        return undefined;
      }

      secretOutcomes.push({
        name: secretName,
        path: formatPath(pathSegments),
        status: 'resolved',
        value: policyOutcome,
      });

      return policyOutcome;
    }

    if (Array.isArray(value)) {
      const output: unknown[] = [];
      for (let index = 0; index < value.length; index += 1) {
        output.push(await walk(value[index], `${path}[${index}]`, [...pathSegments, index]));
      }
      return output;
    }

    if (value && typeof value === 'object') {
      const output: Record<string, unknown> = {};
      for (const [key, nested] of Object.entries(value)) {
        output[key] = await walk(nested, path ? `${path}.${key}` : key, [...pathSegments, key]);
      }
      return output;
    }

    return value;
  }

  return {
    config: (await walk(config, 'config', [])) as T,
    degraded,
    degradedPaths,
    secretOutcomes,
  };
}

export { SecretCache } from './cache';
export { loadEncryptionKey } from './key-loader';
export { applySecretPolicy } from './policy';
export { type DegradedMarker, SecretsError, type SecretRef, type SecretStore } from './types';

interface CacheEntry {
  value: string;
  expiresAt: number;
}

export class SecretCache {
  private readonly cache = new Map<string, CacheEntry>();

  get(name: string): string | undefined {
    const entry = this.cache.get(name);
    if (!entry) {
      return undefined;
    }

    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(name);
      return undefined;
    }

    return entry.value;
  }

  set(name: string, value: string, ttlMs: number): void {
    this.cache.set(name, {
      value,
      expiresAt: Date.now() + ttlMs,
    });
  }

  invalidate(name: string): void {
    this.cache.delete(name);
  }
}

import { readFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import { SecretsError } from './types';

export async function loadEncryptionKey(): Promise<Buffer> {
  const envKey = process.env.LIFEOS_MASTER_KEY?.trim();
  if (envKey) {
    return Buffer.from(envKey, 'utf8');
  }

  const thisFile = fileURLToPath(import.meta.url);
  const rootDir = resolve(dirname(thisFile), '../../../');
  const keyPath = resolve(rootDir, '.secrets/master.key');

  try {
    const key = (await readFile(keyPath, 'utf8')).trim();
    if (!key) {
      throw new SecretsError(`Encryption key file is empty at ${keyPath}.`);
    }
    return Buffer.from(key, 'utf8');
  } catch {
    throw new SecretsError(
      'Unable to load master encryption key. Set LIFEOS_MASTER_KEY or create .secrets/master.key.',
    );
  }
}

export interface SecretStore {
  get(name: string): Promise<string | null>;
  set(name: string, value: string): Promise<void>;
}

export interface SecretRef {
  name: string;
  policy: 'required' | 'optional' | 'required_if_feature_enabled';
  featureGate?: string;
  configPath?: string;
}

export interface DegradedMarker {
  degraded: true;
  reason: string;
}

export class SecretsError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'SecretsError';
  }
}

import type { DegradedMarker, SecretRef } from './types';
import { SecretsError } from './types';

export function applySecretPolicy(
  ref: SecretRef,
  value: string | null,
  featureEnabled?: boolean,
): string | DegradedMarker {
  const pathDetails = ref.configPath ? ` at ${ref.configPath}` : '';

  if (ref.policy === 'required') {
    if (value === null) {
      throw new SecretsError(`Missing required secret '${ref.name}'${pathDetails}.`);
    }
    return value;
  }

  if (ref.policy === 'optional') {
    if (value === null) {
      return {
        degraded: true,
        reason: `Optional secret '${ref.name}' is unavailable${pathDetails}.`,
      };
    }
    return value;
  }

  if (featureEnabled === true) {
    if (value === null) {
      throw new SecretsError(
        `Missing required secret '${ref.name}' for enabled feature '${ref.featureGate ?? 'unknown'}'${pathDetails}.`,
      );
    }
    return value;
  }

  if (value === null) {
    return {
      degraded: true,
      reason: `Secret '${ref.name}' is not loaded because feature '${ref.featureGate ?? 'unknown'}' is disabled${pathDetails}.`,
    };
  }

  return value;
}

export { livenessHandler, readinessHandler, startupHandler } from './endpoints';
export { HealthRegistry } from './registry';
export type { HealthCheck, HealthCheckResult, HealthStatus } from './types';

import type { HealthStatus } from './types';
import { HealthRegistry } from './registry';

interface HandlerResponse {
  status: number;
  body: Record<string, unknown>;
}

function collectReasons(status: HealthStatus): string[] {
  return Object.entries(status.checks)
    .filter(([, value]) => value.reason)
    .map(([name, value]) => `${name}: ${value.reason as string}`);
}

export function livenessHandler(registry: HealthRegistry): () => Promise<HandlerResponse> {
  void registry;
  return async () => ({
    status: 200,
    body: {
      status: 'healthy',
    },
  });
}

export function readinessHandler(registry: HealthRegistry): () => Promise<HandlerResponse> {
  return async () => {
    const status = await registry.runAll();
    const reasons = collectReasons(status);

    return {
      status: status.status === 'healthy' ? 200 : 503,
      body: {
        status: status.status,
        checks: status.checks,
        reasons,
      },
    };
  };
}

export function startupHandler(registry: HealthRegistry): () => Promise<HandlerResponse> {
  return async () => {
    const status = await registry.runAll();
    const reasons = collectReasons(status);

    return {
      status: status.status === 'healthy' ? 200 : 503,
      body: {
        status: status.status,
        checks: status.checks,
        reasons,
      },
    };
  };
}

import type { HealthCheck, HealthCheckResult, HealthStatus } from './types';

export class HealthRegistry {
  private readonly checks = new Map<string, HealthCheck['check']>();

  register(check: HealthCheck): void {
    this.checks.set(check.name, check.check);
  }

  async runAll(): Promise<HealthStatus> {
    const entries = [...this.checks.entries()];
    const results = await Promise.all(
      entries.map(async ([name, check]) => {
        try {
          const result = await check();
          return [name, result] as const;
        } catch (error) {
          const reason = error instanceof Error ? error.message : 'Health check failed.';
          const failed: HealthCheckResult = {
            status: 'unhealthy',
            reason,
          };
          return [name, failed] as const;
        }
      }),
    );

    const checks: Record<string, HealthCheckResult> = Object.fromEntries(results);
    const statuses = Object.values(checks).map((result) => result.status);

    const status = statuses.includes('unhealthy')
      ? 'unhealthy'
      : statuses.includes('degraded')
        ? 'degraded'
        : 'healthy';

    return {
      status,
      checks,
    };
  }
}

export * from './types';

import { randomUUID } from 'node:crypto';

import type { AutomationFailureSpanInput, ObservabilityClient } from './types';
import type { ObservabilityConfig, TraceContext } from './types';

interface LogEntry {
  level: 'debug' | 'info' | 'warn' | 'error';
  message: string;
  serviceName: string;
  environment: string;
  timestamp: string;
  meta?: Record<string, unknown>;
}

function normalizeConfig(config?: Partial<ObservabilityConfig>): ObservabilityConfig {
  const serviceName = config?.serviceName?.trim();
  const environment = config?.environment?.trim();
  if (!serviceName) {
    throw new Error('observability config requires serviceName');
  }
  if (!environment) {
    throw new Error('observability config requires environment');
  }

  return {
    serviceName,
    environment,
    ...(config?.endpoint?.trim() ? { endpoint: config.endpoint.trim() } : {}),
  };
}

function createTraceId(): string {
  return randomUUID().replace(/-/g, '');
}

function createSpanId(): string {
  return randomUUID().replace(/-/g, '').slice(0, 16);
}

function shouldLogToStdout(level: LogEntry['level']): boolean {
  const configured = (process.env.LIFEOS_OBSERVABILITY_STDOUT ?? 'true').trim().toLowerCase();
  if (configured === 'false' || configured === '0') {
    return level === 'error' || level === 'warn';
  }
  return true;
}

function writeLog(entry: LogEntry): void {
  if (!shouldLogToStdout(entry.level)) {
    return;
  }

  const serialized = JSON.stringify(entry);
  if (entry.level === 'error' || entry.level === 'warn') {
    process.stderr.write(`${serialized}\n`);
    return;
  }
  process.stdout.write(`${serialized}\n`);
}

export function createObservabilityClient(config?: ObservabilityConfig): ObservabilityClient {
  const resolved = normalizeConfig(config);
  const spanStartTimes = new Map<string, number>();

  return {
    startSpan(name: string, context?: TraceContext): TraceContext {
      const span = {
        traceId: context?.traceId ?? createTraceId(),
        spanId: createSpanId(),
        ...(context?.spanId ? { parentSpanId: context.spanId } : {}),
      };

      spanStartTimes.set(span.spanId, Date.now());
      writeLog({
        level: 'debug',
        message: `span.start:${name}`,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          traceId: span.traceId,
          spanId: span.spanId,
          parentSpanId: span.parentSpanId,
        },
      });

      return span;
    },

    endSpan(context: TraceContext): void {
      const startedAt = spanStartTimes.get(context.spanId);
      spanStartTimes.delete(context.spanId);
      const durationMs = startedAt ? Date.now() - startedAt : undefined;

      writeLog({
        level: 'debug',
        message: 'span.end',
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          traceId: context.traceId,
          spanId: context.spanId,
          ...(context.parentSpanId ? { parentSpanId: context.parentSpanId } : {}),
          ...(durationMs !== undefined ? { durationMs } : {}),
        },
      });
    },

    recordMetric(name: string, value: number, tags?: Record<string, string>): void {
      writeLog({
        level: 'info',
        message: `metric:${name}`,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        meta: {
          value,
          ...(tags ? { tags } : {}),
        },
      });
    },

    log(
      level: 'debug' | 'info' | 'warn' | 'error',
      message: string,
      meta?: Record<string, unknown>,
    ): void {
      writeLog({
        level,
        message,
        serviceName: resolved.serviceName,
        environment: resolved.environment,
        timestamp: new Date().toISOString(),
        ...(meta ? { meta } : {}),
      });
    },
  };
}

export function emitAutomationFailureSpan(
  client: ObservabilityClient,
  spanName: string,
  input: AutomationFailureSpanInput,
): TraceContext {
  const span = client.startSpan(spanName);
  client.log('error', `automation.failure:${input.errorCode}`, {
    traceId: span.traceId,
    spanId: span.spanId,
    parentSpanId: span.parentSpanId,
    household_id: input.householdId,
    actor_id: input.actorId,
    action_type: input.actionType,
    error_code: input.errorCode,
    fix_suggestion: input.fixSuggestion,
    ...(input.objectId ? { object_id: input.objectId } : {}),
    ...(input.objectRef ? { object_ref: input.objectRef } : {}),
    ...(input.details ? input.details : {}),
  });
  client.endSpan(span);
  return span;
}

export interface TraceContext {
  traceId: string;
  spanId: string;
  parentSpanId?: string;
}

export interface ObservabilityConfig {
  serviceName: string;
  environment: string;
  endpoint?: string;
}

export interface AutomationFailureSpanInput {
  householdId: string;
  actorId: string;
  actionType: string;
  errorCode: string;
  fixSuggestion: string;
  objectId?: string;
  objectRef?: string;
  details?: Record<string, unknown>;
}

export interface ObservabilityClient {
  startSpan(name: string, context?: TraceContext): TraceContext;
  endSpan(context: TraceContext): void;
  recordMetric(name: string, value: number, tags?: Record<string, string>): void;
  log(
    level: 'debug' | 'info' | 'warn' | 'error',
    message: string,
    meta?: Record<string, unknown>,
  ): void;
}

export * from './types';

import type { PolicyClient, PolicyRequest, PolicyResult } from './types';

const POLICY_ID_DEFAULT = 'lifeos.policy.default.v1';
const MODULE_LOAD_ACTION = 'module.load';
const MODULE_LOAD_RESOURCE = 'lifeos.module';
const MAX_PERMISSION_LIST_SIZE = 64;
const ALLOWED_GRAPH_PERMISSIONS = new Set(['read', 'append', 'write']);
const ALLOWED_VOICE_PERMISSIONS = new Set(['speak', 'listen']);
const EVENT_PERMISSION_PATTERN = /^(subscribe|publish):[A-Za-z0-9.*>_-]+(?:\.[A-Za-z0-9.*>_-]+)*$/;
const NETWORK_PERMISSION_PATTERN = /^[a-z0-9][a-z0-9._-]{1,40}$/;
const WILDCARD_TRUSTED_MODULES = new Set(['orchestrator', 'sync-core']);
const SCOPE_ALIAS: Record<string, string> = {
  life_graph_read: 'graph.read',
  life_graph_write: 'graph.write',
  event_publish: 'event.publish',
  event_subscribe: 'event.subscribe',
  llm_access: 'llm.invoke',
  llm_invoke: 'llm.invoke',
};

type PermissionBlock = {
  graph?: unknown;
  voice?: unknown;
  network?: unknown;
  events?: unknown;
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function toStringArray(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return [];
  }
  return value
    .map((entry) => (typeof entry === 'string' ? entry.trim() : ''))
    .filter((entry) => entry.length > 0);
}

function deny(reason: string, policyId = POLICY_ID_DEFAULT): PolicyResult {
  return {
    allowed: false,
    reason,
    policy_id: policyId,
  };
}

function allow(policyId = POLICY_ID_DEFAULT): PolicyResult {
  return {
    allowed: true,
    policy_id: policyId,
  };
}

function parseEventPermission(
  permission: string,
): { action: 'subscribe' | 'publish'; topic: string } | null {
  const [action, topic] = permission.split(':', 2);
  if (!action || !topic || (action !== 'subscribe' && action !== 'publish')) {
    return null;
  }

  return {
    action,
    topic,
  };
}

function evaluateModuleLoadPolicy(subject: string, rawPermissions: PermissionBlock): PolicyResult {
  const graphPermissions = toStringArray(rawPermissions.graph);
  const voicePermissions = toStringArray(rawPermissions.voice);
  const networkPermissions = toStringArray(rawPermissions.network);
  const eventPermissions = toStringArray(rawPermissions.events);

  if (
    graphPermissions.length > MAX_PERMISSION_LIST_SIZE ||
    voicePermissions.length > MAX_PERMISSION_LIST_SIZE ||
    networkPermissions.length > MAX_PERMISSION_LIST_SIZE ||
    eventPermissions.length > MAX_PERMISSION_LIST_SIZE
  ) {
    return deny('permission list exceeds policy limits', 'lifeos.policy.module.permissions.v1');
  }

  for (const permission of graphPermissions) {
    if (!ALLOWED_GRAPH_PERMISSIONS.has(permission)) {
      return deny(
        `graph permission "${permission}" is not allowed`,
        'lifeos.policy.module.permissions.v1',
      );
    }
  }

  for (const permission of voicePermissions) {
    if (!ALLOWED_VOICE_PERMISSIONS.has(permission)) {
      return deny(
        `voice permission "${permission}" is not allowed`,
        'lifeos.policy.module.permissions.v1',
      );
    }
  }

  for (const permission of networkPermissions) {
    if (!NETWORK_PERMISSION_PATTERN.test(permission)) {
      return deny(
        `network permission "${permission}" is malformed`,
        'lifeos.policy.module.permissions.v1',
      );
    }
  }

  for (const permission of eventPermissions) {
    if (!EVENT_PERMISSION_PATTERN.test(permission)) {
      return deny(
        `event permission "${permission}" must be subscribe:<topic> or publish:<topic>`,
        'lifeos.policy.module.permissions.v1',
      );
    }

    const parsed = parseEventPermission(permission);
    if (!parsed) {
      return deny(
        `event permission "${permission}" is malformed`,
        'lifeos.policy.module.permissions.v1',
      );
    }

    if (parsed.action === 'publish' && (parsed.topic.includes('*') || parsed.topic.includes('>'))) {
      return deny(
        `event permission "${permission}" is too broad; publish permissions cannot contain "*" or ">"`,
        'lifeos.policy.module.permissions.v1',
      );
    }

    if (
      parsed.action === 'subscribe' &&
      (parsed.topic.includes('*') || parsed.topic.includes('>')) &&
      !WILDCARD_TRUSTED_MODULES.has(subject)
    ) {
      return deny(
        `event permission "${permission}" is too broad for module "${subject}"`,
        'lifeos.policy.module.permissions.v1',
      );
    }
  }

  return allow('lifeos.policy.module.permissions.v1');
}

function normalizeScopes(scopes: unknown): string[] {
  if (!Array.isArray(scopes)) {
    return [];
  }

  return scopes
    .map((scope) => (typeof scope === 'string' ? scope.trim().toLowerCase() : ''))
    .filter((scope) => scope.length > 0);
}

function resolveScopeCandidates(scope: string): string[] {
  const normalized = scope.trim().toLowerCase();
  const candidates = new Set<string>([normalized]);
  const alias = SCOPE_ALIAS[normalized];
  if (alias) {
    candidates.add(alias);
  }

  return Array.from(candidates);
}

function checkScope(scope: string, request: PolicyRequest): boolean {
  const contextScopes = normalizeScopes(request.context?.scopes);
  const requestScopes = normalizeScopes((request as unknown as { scopes?: unknown }).scopes);
  const merged = new Set<string>([...contextScopes, ...requestScopes]);
  const candidates = resolveScopeCandidates(scope);
  return candidates.some((candidate) => merged.has(candidate));
}

export function createPolicyClient(): PolicyClient {
  const strictMode = (process.env.LIFEOS_POLICY_STRICT ?? 'true').trim().toLowerCase() !== 'false';

  const evaluatePolicy = async (request: PolicyRequest): Promise<PolicyResult> => {
    try {
      if (!isRecord(request)) {
        return deny('invalid policy request shape');
      }

      const subject = request.subject?.trim();
      const action = request.action?.trim();
      const resource = request.resource?.trim();
      const context = isRecord(request.context) ? request.context : {};

      if (!subject || !action || !resource) {
        return deny('policy request must include subject, action, and resource');
      }

      if (action === MODULE_LOAD_ACTION && resource === MODULE_LOAD_RESOURCE) {
        const permissions = isRecord(context.permissions)
          ? (context.permissions as PermissionBlock)
          : {};
        return evaluateModuleLoadPolicy(subject, permissions);
      }

      if (!strictMode) {
        return allow('lifeos.policy.compat.allow.v1');
      }

      const scopes = normalizeScopes(context.scopes);
      if (scopes.includes('*') || scopes.includes('policy:allow')) {
        return allow();
      }

      return deny(`no matching policy rule for ${action} on ${resource}`);
    } catch (error: unknown) {
      const reason = error instanceof Error ? error.message : String(error);
      return deny(`policy evaluation failed: ${reason}`);
    }
  };

  return {
    async evaluatePolicy(request: PolicyRequest): Promise<PolicyResult> {
      return evaluatePolicy(request);
    },
    checkPermission(scope: string, context: PolicyRequest): boolean {
      try {
        return checkScope(scope, context);
      } catch {
        return false;
      }
    },
    async evaluate(request: PolicyRequest): Promise<PolicyResult> {
      return evaluatePolicy(request);
    },
  };
}

export interface PolicyRequest {
  subject: string;
  action: string;
  resource: string;
  context: Record<string, unknown>;
}

export interface PolicyResult {
  allowed: boolean;
  reason?: string;
  policy_id?: string;
}

export const PermissionScope = {
  health_data: 'health_data',
  calendar_write: 'calendar_write',
