const MAX_COMMAND_TEXT_CHARS = 600;
const MAX_TRANSCRIPT_TEXT_CHARS = 2000;
const DEFAULT_WAKE_AUDIO_SECONDS = 5;

function normalizeWakeAudioSeconds(value: number | undefined): number {
  if (!Number.isFinite(value)) {
    return DEFAULT_WAKE_AUDIO_SECONDS;
  }
  return Math.max(1, Math.min(10, Math.round(value as number)));
}

export interface VoiceCoreOptions {
  env?: NodeJS.ProcessEnv;
  graphPath?: string;
  armedTimeoutMs?: number;
  logger?: (message: string) => void;
  publish?: VoiceEventPublisher;
  now?: () => Date;
  router?: IntentRouter;
  routerOptions?: IntentRouterOptions;
  speechToText?: SpeechToText;
  speechToTextOptions?: SpeechToTextOptions;
  textToSpeech?: TextToSpeech;
  textToSpeechOptions?: TextToSpeechOptions;
  wakeWordDetector?: WakeWordDetector;
  wakeWordDetectorOptions?: WakeWordDetectorOptions;
  consentManager?: Pick<ConsentManager, 'hasConsent'>;
  audioRecorder?: AudioRecorder;
  audioRecorderOptions?: AudioRecorderOptions;
  captureWakeAudio?: boolean;
  wakeAudioSeconds?: number;
}

export class VoiceCore {
  private readonly detector: WakeWordDetector;
  private readonly stt: SpeechToText;
  private readonly router: IntentRouter;
  private readonly tts: TextToSpeech;
  private readonly armedTimeoutMs: number;
  private readonly logger: (message: string) => void;
  private readonly publish: VoiceEventPublisher;
  private readonly now: () => Date;
  private readonly consentManager: Pick<ConsentManager, 'hasConsent'>;
  private readonly audioRecorder: AudioRecorder;
  private readonly captureWakeAudio: boolean;
  private readonly wakeAudioSeconds: number;
  private capturingWakeCommand = false;
  private listeningUntil: number | null = null;
  private started = false;
  private closed = false;
  private wakeCaptureTask: Promise<IntentOutcome | null> | null = null;

  constructor(options: VoiceCoreOptions = {}) {
    this.detector =
      options.wakeWordDetector ?? new WakeWordDetector(options.wakeWordDetectorOptions);
    this.stt = options.speechToText ?? new SpeechToText(options.speechToTextOptions);
    this.tts = options.textToSpeech ?? new TextToSpeech(options.textToSpeechOptions);
    this.publish =
      options.publish ??
      options.routerOptions?.publish ??
      (async () => {
        return;
      });
    this.now = options.now ?? (() => new Date());
    this.logger = options.logger ?? (() => undefined);
    const routerOptions: IntentRouterOptions = {
      publish: this.publish,
      now: this.now,
      logger: this.logger,
      ...(options.routerOptions ?? {}),
    };
    if (options.env) {
      routerOptions.env = options.env;
    }
    if (options.graphPath) {
      routerOptions.graphPath = options.graphPath;
    }
    this.router = options.router ?? new IntentRouter(routerOptions);
    this.armedTimeoutMs = options.armedTimeoutMs ?? 10_000;
    this.consentManager = options.consentManager ?? consent;
    this.audioRecorder = options.audioRecorder ?? new AudioRecorder(options.audioRecorderOptions);
    const envCaptureWakeAudio = options.env?.LIFEOS_VOICE_CAPTURE_WAKE_AUDIO?.trim();
    this.captureWakeAudio =
      options.captureWakeAudio ?? (envCaptureWakeAudio ? envCaptureWakeAudio !== '0' : true);
    this.wakeAudioSeconds = normalizeWakeAudioSeconds(options.wakeAudioSeconds);
  }

  getWakePhrase(): string {
    return this.detector.getPrimaryWakePhrase();
  }

  async start(): Promise<void> {
    if (this.closed) {
      throw new Error('Voice core is closed and cannot be restarted.');
    }
    if (this.started) {
      return;
    }
    if (!(await this.consentManager.hasConsent())) {
      throw new MissingMicrophoneConsentError();
    }

    await this.stt.start(async (event) => {
      if (this.closed) {
        return;
      }
      try {
        await this.processTranscript(event);
      } catch (error: unknown) {
        const message = error instanceof Error ? error.message : String(error);
        this.logger(`[voice] transcript processing degraded: ${message}`);
      }
    });
    this.started = true;
  }

  async runDemo(text: string): Promise<IntentOutcome | null> {
    return this.processTranscript({
      text,
      confidence: 1,
    });
  }

  async close(): Promise<void> {
    this.closed = true;
    this.listeningUntil = null;
    this.started = false;

    try {
      await this.stt.stop();
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger(`[voice] stt shutdown degraded: ${message}`);
    }

    if (this.wakeCaptureTask) {
      await this.wakeCaptureTask.catch(() => null);
      this.wakeCaptureTask = null;
    }
  }

  private async processTranscript(event: TranscriptEvent): Promise<IntentOutcome | null> {
    if (this.closed || this.capturingWakeCommand) {
      return null;
    }

    const spokenText = event.text.trim();
    if (!spokenText) {
      return null;
    }

    const detected = this.detector.detect(spokenText);
    if (detected.kind === 'wake_only') {
      await this.publishSafe(
        Topics.lifeos.voiceWakeDetected,
        {
          text: spokenText,
          confidence: event.confidence,
        },
        'voice-core',
      );
      await this.speakSafely('Listening.');

      if (this.captureWakeAudio) {
        this.wakeCaptureTask = this.onWake();
        let capturedOutcome: IntentOutcome | null = null;
        try {
          capturedOutcome = await this.wakeCaptureTask;
        } finally {
          this.wakeCaptureTask = null;
        }
        if (capturedOutcome) {
          return capturedOutcome;
        }
      }

      this.listeningUntil = this.now().getTime() + this.armedTimeoutMs;
      return null;
    }

    const nowMs = this.now().getTime();
    const armed = this.listeningUntil !== null && nowMs <= this.listeningUntil;
    const commandText =
      detected.kind === 'wake_with_command' ? detected.command : armed ? spokenText : null;

    if (!commandText) {
      return null;
    }

    return this.processCommand(commandText, spokenText, event.confidence, {
      source: detected.kind === 'wake_with_command' ? 'wake_inline' : 'armed_fallback',
    });
  }

  private async onWake(): Promise<IntentOutcome | null> {
    if (this.closed || this.capturingWakeCommand) {
      return null;
    }

    this.capturingWakeCommand = true;
    try {
      this.logger('🎤 Listening...');
      const audio = await this.audioRecorder.record(this.wakeAudioSeconds);
      const commandText = (await this.stt.transcribe(audio)).trim();
      if (!commandText) {
        this.logger(
          '[voice] wake capture produced no transcription; waiting for fallback transcript',
        );
        await this.speakSafely("I didn't catch that. Please repeat.");
        return null;
      }

      this.logger(`You said: "${commandText}"`);
      const outcome = await this.processCommand(commandText, commandText, 1, {
        source: 'audio_transcription',
        audioBytes: audio.length,
      });
      if (!outcome.responseText.trim()) {
        await this.speakSafely('Understood.');
      }
      return outcome;
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger(`[voice] wake audio transcription degraded: ${message}`);
      return null;
    } finally {
      this.capturingWakeCommand = false;
    }
  }

  private async processCommand(
    commandText: string,
    transcript: string,
    confidence: number,
    metadata: Record<string, unknown> = {},
  ): Promise<IntentOutcome> {
    const normalizedCommandText = commandText.trim().slice(0, MAX_COMMAND_TEXT_CHARS);
    const normalizedTranscript = transcript.trim().slice(0, MAX_TRANSCRIPT_TEXT_CHARS);
    if (!normalizedCommandText) {
      return {
        handled: false,
        action: 'unhandled',
        responseText: "I didn't catch a command.",
      };
    }

    this.listeningUntil = null;
    this.logger(`[voice] command heard: ${normalizedCommandText}`);
    await this.publishSafe(
      Topics.lifeos.voiceCommandReceived,
      {
        text: normalizedCommandText,
        transcript: normalizedTranscript,
        confidence,
        ...metadata,
      },
      'voice-core',
    );

    let outcome: IntentOutcome;
    try {
      outcome = await this.router.handleCommand(normalizedCommandText);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger(`[voice] router degraded: ${message}`);
      await this.publishSafe(
        Topics.lifeos.voiceCommandUnhandled,
        {
          text: normalizedCommandText,
          reason: message,
        },
        'voice-core',
      );
      outcome = {
        handled: false,
        action: 'unhandled',
        responseText: 'I ran into an internal error while handling that command.',
      };
    }

    const spokenResponse = outcome.responseText.trim();
    if (spokenResponse) {
      await this.speakSafely(spokenResponse);
    }
    return outcome;
  }

  private async speakSafely(text: string): Promise<void> {
    if (!text.trim()) {
      return;
    }

    try {
      await this.tts.speak(text);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger(`[voice] tts degraded: ${message}`);
    }
  }

  private async publishSafe(
    topic: string,
    data: Record<string, unknown>,
    source: string,
  ): Promise<void> {
    try {
      await this.publish(topic, data, source);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger(`[voice] publish degraded topic=${topic}: ${message}`);
    }
  }
}

export function createVoiceCore(options: VoiceCoreOptions = {}): VoiceCore {
  return new VoiceCore(options);
}

import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { homedir } from 'node:os';
import { dirname, join } from 'node:path';

interface ConsentDocument {
  mic?: boolean;
  grantedAt?: string;
}

const DEFAULT_CONSENT_PATH = join(homedir(), '.lifeos', 'consent.json');

function resolveConsentPath(): string {
  const overridePath = process.env.LIFEOS_CONSENT_PATH?.trim();
  return overridePath && overridePath.length > 0 ? overridePath : DEFAULT_CONSENT_PATH;
}

export class MissingMicrophoneConsentError extends Error {
  constructor(message = 'Microphone access required. Run: pnpm lifeos voice consent') {
    super(message);
    this.name = 'MissingMicrophoneConsentError';
  }
}

export class ConsentManager {
  private readonly consentPath: string;

  constructor(consentPath = resolveConsentPath()) {
    this.consentPath = consentPath;
  }

  async hasConsent(): Promise<boolean> {
    try {
      const raw = await readFile(this.consentPath, 'utf8');
      const data = JSON.parse(raw) as ConsentDocument;
      return data.mic === true;
    } catch {
      return false;
    }
  }

  async grantConsent(): Promise<void> {
    await mkdir(dirname(this.consentPath), { recursive: true });
    await writeFile(
      this.consentPath,
      `${JSON.stringify({ mic: true, grantedAt: new Date().toISOString() }, null, 2)}\n`,
      'utf8',
    );
  }
}

export const consent = new ConsentManager();

import { setTimeout as delay } from 'node:timers/promises';

export class AudioRecorderError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'AudioRecorderError';
  }
}

export interface AudioRecorderOptions {
  sampleRate?: number;
  channels?: number;
  endGraceMs?: number;
  maxSeconds?: number;
  logger?: (message: string) => void;
}

interface NodeRecordSession {
  stream(): NodeJS.ReadableStream;
  stop(): void;
}

interface NodeRecordModule {
  record(options: { sampleRate: number; channels: number }): NodeRecordSession;
}

let cachedNodeRecordModule: Promise<NodeRecordModule> | null = null;

function resolveNodeRecordModule(moduleLike: unknown): NodeRecordModule | null {
  if (
    moduleLike &&
    typeof moduleLike === 'object' &&
    'record' in moduleLike &&
    typeof (moduleLike as { record?: unknown }).record === 'function'
  ) {
    return moduleLike as NodeRecordModule;
  }

  return null;
}

async function loadNodeRecordModule(): Promise<NodeRecordModule> {
  if (!cachedNodeRecordModule) {
    cachedNodeRecordModule = (async () => {
      let recorderModuleLike: unknown;
      try {
        recorderModuleLike = await import('node-record-lpcm16');
      } catch {
        throw new AudioRecorderError(
          'Missing `node-record-lpcm16` dependency. Install with: pnpm add node-record-lpcm16 -F @lifeos/voice-core',
        );
      }

      const resolved =
        resolveNodeRecordModule((recorderModuleLike as { default?: unknown }).default) ??
        resolveNodeRecordModule(recorderModuleLike);
      if (!resolved) {
        throw new AudioRecorderError('Unable to initialize node-record-lpcm16.');
      }
      return resolved;
    })();
  }

  return cachedNodeRecordModule;
}

export class AudioRecorder {
  private readonly sampleRate: number;
  private readonly channels: number;
  private readonly endGraceMs: number;
  private readonly maxSeconds: number;
  private readonly logger: (message: string) => void;

  constructor(options: AudioRecorderOptions = {}) {
    this.sampleRate = options.sampleRate ?? 16000;
    this.channels = options.channels ?? 1;
    this.endGraceMs = options.endGraceMs ?? 500;
    this.maxSeconds = options.maxSeconds ?? 12;
    this.logger = options.logger ?? (() => undefined);
  }

  async record(seconds = 4): Promise<Buffer> {
    if (!Number.isFinite(this.sampleRate) || this.sampleRate <= 0) {
      throw new AudioRecorderError('Recorder sampleRate must be a positive number.');
    }
    if (!Number.isFinite(this.channels) || this.channels <= 0) {
      throw new AudioRecorderError('Recorder channels must be a positive number.');
    }
    if (!Number.isFinite(seconds) || seconds <= 0) {
      throw new AudioRecorderError('Recording duration must be a positive number.');
    }
    if (seconds > this.maxSeconds) {
      throw new AudioRecorderError(`Recording duration exceeds safety max (${this.maxSeconds}s).`);
    }

    const resolved = await loadNodeRecordModule();

    return new Promise<Buffer>((resolve, reject) => {
      let settled = false;
      const chunks: Buffer[] = [];
      let finalizeTimer: ReturnType<typeof setTimeout> | null = null;

      const finishResolve = (buffer: Buffer): void => {
        if (settled) {
          return;
        }
        settled = true;
        if (finalizeTimer) {
          clearTimeout(finalizeTimer);
        }
        if (buffer.length === 0) {
          reject(new AudioRecorderError('Microphone recording produced no audio.'));
          return;
        }
        resolve(buffer);
      };

      const finishReject = (error: unknown): void => {
        if (settled) {
          return;
        }
        settled = true;
        if (finalizeTimer) {
          clearTimeout(finalizeTimer);
        }
        const message = error instanceof Error ? error.message : String(error);
        reject(new AudioRecorderError(`Microphone recording failed: ${message}`));
      };

      let session: NodeRecordSession;
      try {
        session = resolved.record({
          sampleRate: this.sampleRate,
          channels: this.channels,
        });
      } catch (error: unknown) {
        finishReject(error);
        return;
      }

      const stream = session.stream();
      stream.on('data', (chunk: Buffer | string) => {
        chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
      });
      stream.once('error', (error) => {
        finishReject(error);
      });
      stream.once('end', () => {
        finishResolve(Buffer.concat(chunks));
      });

      void (async () => {
        await delay(Math.ceil(seconds * 1000));
        try {
          session.stop();
        } catch (error: unknown) {
          finishReject(error);
          return;
        }

        finalizeTimer = setTimeout(() => {
          this.logger('[voice.recorder] stream end timeout, resolving with buffered audio.');
          finishResolve(Buffer.concat(chunks));
        }, this.endGraceMs);
      })();
    });
  }
}

import { randomUUID } from 'node:crypto';

import { Topics } from '@lifeos/event-bus';
import { createLifeGraphClient, type LifeGraphClient } from '@lifeos/life-graph';

const MAX_TASK_TITLE_CHARS = 160;
const MAX_COMMAND_TEXT_CHARS = 600;
const MAX_DESCRIPTION_CHARS = 1200;
const MAX_CALENDAR_TITLE_CHARS = 200;
const MAX_LOCATION_CHARS = 200;
const MAX_ATTENDEES = 20;
const MAX_ATTENDEE_CHARS = 120;
const MAX_NOTE_TITLE_CHARS = 200;
const MAX_NOTE_CONTENT_CHARS = 2000;
const MAX_NOTE_TAGS = 20;
const MAX_NOTE_TAG_CHARS = 40;
const MAX_PREFERENCE_KEY_CHARS = 80;
const MAX_PREFERENCE_VALUE_CHARS = 300;
const MIN_BRIEFING_SECONDS = 10;
const MAX_BRIEFING_SECONDS = 90;
const DATE_ONLY_PATTERN = /^\d{4}-\d{2}-\d{2}$/;
// Security: Prevent injection patterns
const INJECTION_PATTERN = /[\0\x00-\x1f\x7f]/;
const PREFERENCE_KEY_ALIASES: Record<
  string,
  | 'communication_style'
  | 'priorities'
  | 'quirks'
  | 'briefing_max_seconds'
  | 'sync_conflict_voice_alerts'
> = {
  communication_style: 'communication_style',
  communicationstyle: 'communication_style',
  style: 'communication_style',
  response_style: 'communication_style',
  briefing_style: 'communication_style',
  briefing_max_seconds: 'briefing_max_seconds',
  briefing_seconds: 'briefing_max_seconds',
  sync_conflict_voice_alerts: 'sync_conflict_voice_alerts',
  sync_conflict_alerts: 'sync_conflict_voice_alerts',
  conflict_alerts: 'sync_conflict_voice_alerts',
  sync_alerts: 'sync_conflict_voice_alerts',
  sync_conflicts: 'sync_conflict_voice_alerts',
  priority: 'priorities',
  priorities: 'priorities',
  quirk: 'quirks',
  quirks: 'quirks',
};

type ClassifiedIntent =
  | 'task_add'
  | 'calendar_add'
  | 'note_add'
  | 'note_search'
  | 'question_time'
  | 'weather'
  | 'news'
  | 'email_summarize'
  | 'research'
  | 'briefing'
  | 'next_actions'
  | 'preference_set'
  | 'health_log'
  | 'health_query'
  | 'unknown';

interface IntentClassification {
  intent: ClassifiedIntent;
  payload: Record<string, unknown>;
}

export const INTENT_PROMPT = `You are LifeOS intent parser. Return ONLY JSON.

{
  "intent": "task_add | calendar_add | note_add | note_search | question_time | weather | news | email_summarize | research | briefing | next_actions | preference_set | health_log | health_query | unknown",
  "payload": {}
}`;

export interface IntentOutcome {
  handled: boolean;
  action:
    | 'task_added'
    | 'next_actions'
    | 'time_reported'
    | 'agent_work_requested'
    | 'preference_updated'
    | 'unhandled';
  responseText: string;
  planId?: string;
  taskId?: string;
}

export type VoiceEventPublisher = (
  topic: string,
  data: Record<string, unknown>,
  source?: string,
) => Promise<void>;

type IntentClassifier = (text: string) => Promise<IntentClassification>;

export interface IntentRouterOptions {
  env?: NodeJS.ProcessEnv;
  graphPath?: string;
  client?: LifeGraphClient;
  createLifeGraphClient?: typeof createLifeGraphClient;
  publish?: VoiceEventPublisher;
  now?: () => Date;
  classifyIntent?: IntentClassifier;
  logger?: (message: string) => void;
  classifierTimeoutMs?: number;
}

function sentenceCase(value: string): string {
  const trimmed = value.trim().replace(/[.?!]+$/g, '');
  if (!trimmed) {
    return 'Untitled task';
  }

  return `${trimmed.charAt(0).toUpperCase()}${trimmed.slice(1)}`;
}

function clampText(value: string, maxLength: number): string {
  return value.trim().slice(0, maxLength);
}

/**
 * Validates text input to prevent injection and ensure data integrity.
 * @throws Error if text contains invalid characters
 */
function validateTextInput(value: string, maxLength: number): string {
  const trimmed = value.trim();

  // Prevent null bytes and other control characters
  if (INJECTION_PATTERN.test(trimmed)) {
    throw new Error('Input contains invalid control characters');
  }

  // Ensure not empty
  if (trimmed.length === 0) {
    throw new Error('Input cannot be empty');
  }

  // Keep long utterances processable while bounding payload size.
  return trimmed.slice(0, maxLength);
}

function getString(value: unknown): string | null {
  if (typeof value !== 'string') {
    return null;
  }

  const trimmed = value.trim();
  // Prevent null bytes
  if (INJECTION_PATTERN.test(trimmed)) {
    return null;
  }
  return trimmed.length > 0 ? trimmed : null;
}

function getStringArray(value: unknown): string[] | null {
  if (!Array.isArray(value)) {
    return null;
  }

  const normalized = value
    .map((entry) => getString(entry))
    .filter((entry): entry is string => entry !== null && !INJECTION_PATTERN.test(entry));
  return normalized.length > 0 ? normalized.slice(0, MAX_ATTENDEES) : null;
}

function getNumber(value: unknown): number | null {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === 'string') {
    const parsed = Number.parseFloat(value);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }
  return null;
}

function parseDateTime(value: unknown): Date | null {
  const candidate = getString(value);
  if (!candidate) {
    return null;
  }

  const parsed = new Date(candidate);
  if (Number.isNaN(parsed.getTime())) {
    return null;
  }

  return parsed;
}

function normalizeCalendarStatus(value: unknown): 'confirmed' | 'tentative' | 'cancelled' {
  if (value === 'tentative' || value === 'cancelled') {
    return value;
  }
  return 'confirmed';
}

function normalizeDueDate(value: unknown): string | null {
  const candidate = getString(value);
  if (!candidate) {
    return null;
  }
  return DATE_ONLY_PATTERN.test(candidate) ? candidate : null;
}

function extractLocationFromText(text: string): string | null {
  const match = text.match(/\b(?:in|for)\s+([a-zA-Z][a-zA-Z\s-]{1,80})/i)?.[1];
  return match ? clampText(match, MAX_LOCATION_CHARS) : null;
}

function extractResearchQuery(text: string): string {
  const stripped = text.replace(
    /^(hey life(?:\s?os)?[,\s]*)?(research|look up|investigate)\s+/i,
    '',
  );
  return clampText(stripped || text, MAX_DESCRIPTION_CHARS);
}

function extractNoteContent(text: string): string {
  const stripped = text.replace(/^(hey life(?:\s?os)?[,\s]*)?(note that|note)\s+/i, '');
  return clampText(stripped || text, MAX_NOTE_CONTENT_CHARS);
}

function extractNoteSearchQuery(text: string): string {
  const stripped = text.replace(
    /^(hey life(?:\s?os)?[,\s]*)?(what did i note about|find notes? about|search notes? for)\s+/i,
    '',
  );
  return clampText(stripped || text, MAX_NOTE_CONTENT_CHARS);
}

function extractSinceDaysFromText(text: string): number | null {
  const lower = text.toLowerCase();
  if (lower.includes('last week')) {
    return 7;
  }
  if (lower.includes('yesterday')) {
    return 1;
  }
  if (lower.includes('last month')) {
    return 30;
  }
  return null;
}

function extractHealthMetricFromText(text: string): string | null {
  const match = text
    .toLowerCase()
    .match(
      /\b(steps?|slept?|sleep(?:ing)?|weight|heart(?:\s|-)?rate|blood(?:\s|-)?pressure|water|calories?)\b/,
    );
  if (!match?.[1]) {
    return null;
  }
  return match[1].replace(/\s+/g, '_');
}

function extractHealthQueryPeriodFromText(text: string): number | null {
  const explicitDays = text.match(/\blast\s+(\d{1,3})\s+days?\b/i)?.[1];
  if (explicitDays) {
    const parsed = Number.parseInt(explicitDays, 10);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }
  return extractSinceDaysFromText(text);
}

function extractPreferenceFromText(text: string): { key: string; value: string } | null {
  const syncConflictDisable =
    /\b(?:disable|turn off|mute|stop|dont|don't|do not)\b[\s\w]{0,40}\b(?:sync )?conflict alerts?\b/i.test(
      text,
    );
  if (syncConflictDisable) {
    return {
      key: 'sync_conflict_voice_alerts',
      value: 'false',
    };
  }

  const syncConflictEnable =
    /\b(?:enable|turn on|alert me|notify me)\b[\s\w]{0,40}\b(?:sync )?conflict alerts?\b/i.test(
      text,
    );
  if (syncConflictEnable) {
    return {
      key: 'sync_conflict_voice_alerts',
      value: 'true',
    };
  }

  const briefingSecondsMatch = text.match(
    /\b(?:keep\s+)?briefings?\s+(?:under|below|<=?|at most)\s*(\d{1,3})\s*seconds?\b/i,
  )?.[1];
  if (briefingSecondsMatch) {
    return {
      key: 'briefing_max_seconds',
      value: briefingSecondsMatch,
    };
  }

  const preferMatch = text.match(/^.*?\bi prefer\s+(.+)$/i)?.[1];
  if (preferMatch) {
    return {
      key: 'communication_style',
      value: clampText(preferMatch, MAX_PREFERENCE_VALUE_CHARS),
    };
  }

  const rememberMatch = text.match(/^.*?\bremember(?: that)? i\s+(.+)$/i)?.[1];
  if (rememberMatch) {
    return {
      key: 'quirks',
      value: clampText(`i ${rememberMatch}`, MAX_PREFERENCE_VALUE_CHARS),
    };
  }

  const prioritizeMatch = text.match(/^.*?\b(?:always\s+)?prioritize\s+(.+)$/i)?.[1];
  if (prioritizeMatch) {
    return {
      key: 'priorities',
      value: clampText(prioritizeMatch, MAX_PREFERENCE_VALUE_CHARS),
    };
  }

  return null;
}

function normalizePreferenceKey(
  raw: string | null,
):
  | 'communication_style'
  | 'priorities'
  | 'quirks'
  | 'briefing_max_seconds'
  | 'sync_conflict_voice_alerts'
  | null {
  if (!raw) {
    return null;
  }
  const normalized = raw
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_\s-]/g, '')
    .replace(/[\s-]+/g, '_')
    .slice(0, MAX_PREFERENCE_KEY_CHARS);
  return PREFERENCE_KEY_ALIASES[normalized] ?? null;
}

function normalizeBriefingSecondsValue(raw: string | null): string | null {
  if (!raw) {
    return null;
  }
  const parsed = Number.parseInt(raw.trim(), 10);
  if (!Number.isFinite(parsed)) {
    return null;
  }
  const bounded = Math.max(MIN_BRIEFING_SECONDS, Math.min(MAX_BRIEFING_SECONDS, parsed));
  return String(bounded);
}

function isResearchFollowUpPhrase(text: string): boolean {
  return /^(tell me more|expand(?: on)?|continue|go deeper|what else|what about|elaborate(?: on)?)\b/i.test(
    text.trim(),
  );
}

function deriveNoteTitle(content: string): string {
  return clampText(
    content.split(/\s+/g).slice(0, 7).join(' ') || 'Voice note',
    MAX_NOTE_TITLE_CHARS,
  );
}

function extractTaskTitle(text: string): string | null {
  const normalized = text.trim();
  const patterns = [
    /^add(?: me)?(?: an?| another)? task(?: to)?\s+(.+)$/i,
    /^remind me to\s+(.+)$/i,
    /^remember to\s+(.+)$/i,
  ];

  for (const pattern of patterns) {
    const match = normalized.match(pattern);
    const candidate = match?.[1]?.trim();
    if (candidate) {
      return sentenceCase(candidate);
    }
  }

  return null;
}

function normalizeClassifiedIntent(value: unknown): ClassifiedIntent {
  if (
    value === 'task_add' ||
    value === 'calendar_add' ||
    value === 'note_add' ||
    value === 'note_search' ||
    value === 'question_time' ||
    value === 'weather' ||
    value === 'news' ||
    value === 'email_summarize' ||
    value === 'research' ||
    value === 'briefing' ||
    value === 'next_actions' ||
    value === 'preference_set' ||
    value === 'health_log' ||
    value === 'health_query' ||
    value === 'health' ||
    value === 'preference' ||
    value === 'preference_update'
  ) {
    if (value === 'preference' || value === 'preference_update') {
      return 'preference_set';
    }
    if (value === 'health') {
      return 'health_log';
    }
    return value;
  }

  return 'unknown';
}

function parseClassificationResponse(raw: string): IntentClassification {
  const parsed = JSON.parse(raw) as unknown;
  if (!parsed || typeof parsed !== 'object') {
    return {
      intent: 'unknown',
      payload: {},
    };
  }

  const candidate = parsed as { intent?: unknown; payload?: unknown };
  const payload =
    candidate.payload && typeof candidate.payload === 'object' && !Array.isArray(candidate.payload)
      ? (candidate.payload as Record<string, unknown>)
      : {};

  return {
    intent: normalizeClassifiedIntent(candidate.intent),
    payload,
  };
}

function normalizeClassification(input: IntentClassification): IntentClassification {
  const payload =
    input.payload && typeof input.payload === 'object' && !Array.isArray(input.payload)
      ? input.payload
      : {};
  return {
    intent: normalizeClassifiedIntent((input as { intent?: unknown }).intent),
    payload,
  };
}

function normalizeErrorMessage(error: unknown): string {
  if (error instanceof Error && error.message.trim()) {
    return error.message;
  }
  return String(error);
}

function resolveClassifierTimeoutMs(
  env: NodeJS.ProcessEnv | undefined,
  configuredTimeoutMs: number | undefined,
): number {
  if (Number.isFinite(configuredTimeoutMs) && (configuredTimeoutMs ?? 0) > 0) {
    return Math.floor(configuredTimeoutMs as number);
  }

  const fromEnv = Number.parseInt(env?.LIFEOS_VOICE_CLASSIFIER_TIMEOUT_MS?.trim() ?? '', 10);
  if (Number.isFinite(fromEnv) && fromEnv > 0) {
    return fromEnv;
  }

  return 4000;
}

function createOllamaIntentClassifier(
  env?: NodeJS.ProcessEnv,
  configuredTimeoutMs?: number,
): IntentClassifier {
  const model = env?.LIFEOS_VOICE_MODEL?.trim() || env?.LIFEOS_GOAL_MODEL?.trim() || 'llama3.1:8b';
  const host = env?.OLLAMA_HOST?.trim() || 'http://127.0.0.1:11434';
  const endpoint = `${host.replace(/\/+$/, '')}/api/chat`;
  const timeoutMs = resolveClassifierTimeoutMs(env, configuredTimeoutMs);

  return async (text: string): Promise<IntentClassification> => {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), timeoutMs);
    let response: Response;
    try {
      response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'content-type': 'application/json',
        },
        body: JSON.stringify({
          model,
          format: 'json',
          stream: false,
          options: {
            temperature: 0.1,
            num_ctx: 4096,
          },
          messages: [
            {
              role: 'system',
              content: INTENT_PROMPT,
            },
            {
              role: 'user',
              content: text.trim().slice(0, 800),
            },
          ],
        }),
        signal: controller.signal,
      });
    } catch (error: unknown) {
      if (
        (error instanceof Error && error.name === 'AbortError') ||
        (typeof error === 'object' &&
          error !== null &&
          'name' in error &&
          (error as { name?: unknown }).name === 'AbortError')
      ) {
        throw new Error(`Intent classification timed out after ${timeoutMs}ms.`);
      }
      throw error;
    } finally {
      clearTimeout(timeout);
    }

    if (!response.ok) {
      throw new Error(`Intent classification failed (${response.status})`);
    }

    const data = (await response.json()) as {
      message?: {
        content?: unknown;
      };
    };
    const content = data.message?.content;
    if (typeof content !== 'string') {
      throw new Error('Intent classifier returned invalid content');
    }

    return parseClassificationResponse(content);
  };
}

async function noopPublish(): Promise<void> {
  return;
}

export class IntentRouter {
  private readonly client: LifeGraphClient;
  private readonly publish: VoiceEventPublisher;
  private readonly now: () => Date;
  private readonly classifyIntent: IntentClassifier;
  private readonly logger: (message: string) => void;

  constructor(options: IntentRouterOptions = {}) {
    const createClient = options.createLifeGraphClient ?? createLifeGraphClient;
    const clientOptions: Parameters<typeof createLifeGraphClient>[0] = {};
    if (options.env) {
      clientOptions.env = options.env;
    }
    if (options.graphPath) {
      clientOptions.graphPath = options.graphPath;
    }
    this.client = options.client ?? createClient(clientOptions);
    this.publish = options.publish ?? noopPublish;
    this.now = options.now ?? (() => new Date());
    this.classifyIntent =
      options.classifyIntent ??
      createOllamaIntentClassifier(options.env, options.classifierTimeoutMs);
    this.logger = options.logger ?? (() => undefined);
  }

  async handleCommand(text: string): Promise<IntentOutcome> {
    // Validate input immediately
    let normalizedText: string;
    try {
      normalizedText = validateTextInput(text, MAX_COMMAND_TEXT_CHARS);
    } catch (error: unknown) {
      this.logger(
        `[voice.router] invalid input: ${error instanceof Error ? error.message : String(error)}`,
      );
      return this.handleUnknownIntent('');
    }

    let classification: IntentClassification = { intent: 'unknown', payload: {} };
    try {
      classification = await this.classifyIntent(normalizedText);
    } catch (error: unknown) {
      this.logger(
        `[voice.router] classifier degraded, using fallback heuristics: ${normalizeErrorMessage(error)}`,
      );
      // Keep command flow local-first even if local LLM is unavailable.
      classification = {
        intent: this.fallbackIntent(normalizedText),
        payload: {},
      };
    }
    classification = normalizeClassification(classification);

    switch (classification.intent) {
      case 'task_add':
        return this.handleTaskAddIntent(normalizedText, classification.payload);
      case 'next_actions':
        return this.handleNextActionsIntent(normalizedText);
      case 'question_time':
        return this.handleTimeIntent(normalizedText);
      case 'calendar_add':
        return this.handleAgentIntent(normalizedText, 'calendar', classification.payload);
      case 'note_add':
        return this.handleAgentIntent(normalizedText, 'note', classification.payload);
      case 'note_search':
        return this.handleAgentIntent(normalizedText, 'note_search', classification.payload);
      case 'weather':
        return this.handleAgentIntent(normalizedText, 'weather', classification.payload);
      case 'news':
        return this.handleAgentIntent(normalizedText, 'news', classification.payload);
      case 'email_summarize':
        return this.handleAgentIntent(normalizedText, 'email_summarize', classification.payload);
      case 'research':
        return this.handleAgentIntent(normalizedText, 'research', classification.payload);
      case 'briefing':
        return this.handleAgentIntent(normalizedText, 'briefing', classification.payload);
      case 'preference_set':
        return this.handlePreferenceIntent(normalizedText, classification.payload);
      case 'health_log':
        return this.handleAgentIntent(normalizedText, 'health_log', classification.payload);
      case 'health_query':
        return this.handleAgentIntent(normalizedText, 'health_query', classification.payload);
      default:
        return this.handleUnknownIntent(normalizedText);
    }
  }

  private fallbackIntent(text: string): ClassifiedIntent {
    const lower = text.toLowerCase();
    if (extractTaskTitle(text)) {
      return 'task_add';
    }
    if (
      lower.includes("what's next") ||
      lower.includes('what is next') ||
      lower.includes('next task')
    ) {
      return 'next_actions';
    }
    if (
      lower.includes('what time is it') ||
      lower.includes("what's the time") ||
      lower === 'time' ||
      lower.includes('current time')
    ) {
      return 'question_time';
    }
    if (lower.includes('calendar') || lower.includes('schedule')) {
      return 'calendar_add';
    }
    if (
      lower.includes('what did i note about') ||
      lower.includes('find note about') ||
      lower.includes('search notes for')
    ) {
      return 'note_search';
    }
    if (lower.startsWith('note ') || lower.includes('note that')) {
      return 'note_add';
    }
    if (lower.includes('weather')) {
      return 'weather';
    }
    if (lower.includes('news') || lower.includes('headlines')) {
      return 'news';
    }
    if (
      lower.includes('email summary') ||
      lower.includes('summarize email') ||
      lower.includes('summarize inbox') ||
      lower.includes('email digest')
    ) {
      return 'email_summarize';
    }
    // Detect health log by either explicit 'log' keyword or numeric + metric pattern
    const metricKeyword = extractHealthMetricFromText(text);
    if (metricKeyword) {
      // Check for numeric value followed by metric (handles "7.5 hours", "72 kg", etc.)
      if (/\d+(?:\.\d+)?/.test(text)) {
        return 'health_log';
      }
    }
    if (
      lower.includes('log') &&
      (lower.includes('steps') ||
        lower.includes('sleep') ||
        lower.includes('weight') ||
        lower.includes('heart rate') ||
        lower.includes('blood pressure') ||
        lower.includes('calories') ||
        lower.includes('water'))
    ) {
      return 'health_log';
    }
    if (
      lower.includes('health') ||
      lower.includes('how many steps') ||
      lower.includes('progress on') ||
      lower.includes('streak')
    ) {
      return 'health_query';
    }
    if (
      extractPreferenceFromText(text) ||
      lower.includes('i prefer') ||
      lower.includes('remember i') ||
      lower.includes('remember that i') ||
      lower.includes('prioritize') ||
      lower.includes('sync conflict alert')
    ) {
      return 'preference_set';
    }
    if (lower.includes('briefing') || lower.includes('good morning')) {
      return 'briefing';
    }
    if (lower.includes('research')) {
      return 'research';
    }
    if (isResearchFollowUpPhrase(text)) {
      return 'research';
    }
    return 'unknown';
  }

  private async handleTaskAddIntent(
    text: string,
    payload: Record<string, unknown>,
  ): Promise<IntentOutcome> {
    const taskTitleRaw =
      getString(payload.title) ??
      getString(payload.task) ??
      getString(payload.name) ??
      extractTaskTitle(text) ??
      sentenceCase(text);
    const taskTitle = clampText(taskTitleRaw, MAX_TASK_TITLE_CHARS) || 'Untitled task';
    const dueDate = normalizeDueDate(payload.dueDate) ?? normalizeDueDate(payload.date);

    return this.handleTaskIntent(text, taskTitle, dueDate);
  }

  private async handleNextActionsIntent(text: string): Promise<IntentOutcome> {
    const review = await this.client.generateReview('daily');
    const firstAction = review.nextActions[0] ?? 'You do not have any queued next actions.';
    const responseText =
      review.nextActions.length > 0 ? `Your next action is ${firstAction}.` : firstAction;

    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'next_actions',
      text,
      responseText,
    });

    return {
      handled: true,
      action: 'next_actions',
      responseText,
    };
  }

  private async handleTimeIntent(text: string): Promise<IntentOutcome> {
    const timeIso = this.now().toISOString();
    const responseText = `Current local time snapshot: ${timeIso}.`;
    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'time_reported',
      text,
      responseText,
      at: timeIso,
    });
    return {
      handled: true,
      action: 'time_reported',
      responseText,
    };
  }

  private async handleAgentIntent(
    text: string,
    intent:
      | 'calendar'
      | 'weather'
      | 'research'
      | 'note'
      | 'news'
      | 'email_summarize'
      | 'note_search'
      | 'briefing'
      | 'health_log'
      | 'health_query',
    payload: Record<string, unknown>,
  ): Promise<IntentOutcome> {
    if (intent === 'calendar') {
      return this.handleCalendarIntent(text, payload);
    }

    const requestedAt = this.now().toISOString();
    const routedPayload = this.buildIntentPayload(intent, text, payload, requestedAt);
    const topicByIntent: Record<
      | 'weather'
      | 'research'
      | 'note'
      | 'news'
      | 'email_summarize'
      | 'note_search'
      | 'briefing'
      | 'health_log'
      | 'health_query',
      string
    > = {
      weather: Topics.lifeos.voiceIntentWeather,
      research: Topics.lifeos.voiceIntentResearch,
      note: Topics.lifeos.voiceIntentNoteAdd,
      news: Topics.lifeos.voiceIntentNews,
      email_summarize: Topics.lifeos.voiceIntentEmailSummarize,
      note_search: Topics.lifeos.voiceIntentNoteSearch,
      briefing: Topics.lifeos.voiceIntentBriefing,
      health_log: Topics.lifeos.voiceIntentHealthLog,
      health_query: Topics.lifeos.voiceIntentHealthQuery,
    };

    await this.publishSafe(topicByIntent[intent], routedPayload);
    if (intent !== 'health_log' && intent !== 'health_query') {
      await this.publishSafe(Topics.agent.workRequested, {
        utterance: text,
        intent,
        payload: routedPayload,
        requestedAt,
        origin: 'voice-core',
      });
    }
    const responseText = this.intentConfirmation(intent, routedPayload);
    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'agent_work_requested',
      text,
      responseText,
      intent,
    });
    return {
      handled: true,
      action: 'agent_work_requested',
      responseText,
    };
  }

  private intentConfirmation(
    intent:
      | 'weather'
      | 'research'
      | 'note'
      | 'news'
      | 'email_summarize'
      | 'note_search'
      | 'briefing'
      | 'health_log'
      | 'health_query',
    payload: Record<string, unknown>,
  ): string {
    if (intent === 'weather') {
      const location = getString(payload.location) ?? 'your location';
      return `Checking weather for ${location}.`;
    }
    if (intent === 'research') {
      const query = getString(payload.query) ?? 'that topic';
      return `Researching ${query}.`;
    }
    if (intent === 'note') {
      return 'Noted. I will save that.';
    }
    if (intent === 'note_search') {
      const query = getString(payload.query) ?? 'that topic';
      return `Searching notes about ${query}.`;
    }
    if (intent === 'briefing') {
      return 'Preparing your daily briefing.';
    }
    if (intent === 'email_summarize') {
      return 'Preparing your email summary.';
    }
    if (intent === 'health_log') {
      return 'Logged. I will update your health tracker.';
    }
    if (intent === 'health_query') {
      return 'Checking your health metrics.';
    }
    return 'Preparing your news digest.';
  }

  private async handlePreferenceIntent(
    text: string,
    payload: Record<string, unknown>,
  ): Promise<IntentOutcome> {
    const parsed = extractPreferenceFromText(text);
    const key =
      normalizePreferenceKey(getString(payload.key)) ??
      normalizePreferenceKey(parsed?.key ?? null) ??
      'communication_style';
    const value = clampText(
      getString(payload.value) ?? parsed?.value ?? '',
      MAX_PREFERENCE_VALUE_CHARS,
    );
    if (!value) {
      return this.handleUnknownIntent(text);
    }
    const normalizedValue =
      key === 'briefing_max_seconds' ? normalizeBriefingSecondsValue(value) : value;
    if (!normalizedValue) {
      return this.handleUnknownIntent(text);
    }
    const requestedAt = this.now().toISOString();
    const normalizedPayload = {
      key,
      value: normalizedValue,
      utterance: text,
      requestedAt,
    };

    await this.publishSafe(Topics.lifeos.voiceIntentPreferenceSet, normalizedPayload);
    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'preference_updated',
      text,
      key,
      value: normalizedValue,
    });

    let responseText = 'Understood. I will remember that preference.';
    if (key === 'communication_style') {
      responseText = 'Understood. I will keep responses concise.';
    } else if (key === 'briefing_max_seconds') {
      responseText = `Understood. I will keep briefings under ${normalizedValue} seconds.`;
    } else if (key === 'sync_conflict_voice_alerts') {
      responseText =
        normalizedValue === 'false'
          ? 'Understood. I will keep sync conflict alerts silent.'
          : 'Understood. I will announce sync conflict alerts.';
    }
    return {
      handled: true,
      action: 'preference_updated',
      responseText,
    };
  }

  private buildIntentPayload(
    intent:
      | 'weather'
      | 'research'
      | 'note'
      | 'news'
      | 'email_summarize'
      | 'note_search'
      | 'briefing'
      | 'health_log'
      | 'health_query',
    text: string,
    payload: Record<string, unknown>,
    requestedAt: string,
  ): Record<string, unknown> {
    if (intent === 'weather') {
      return {
        location: clampText(
          getString(payload.location) ?? extractLocationFromText(text) ?? 'current',
          MAX_LOCATION_CHARS,
        ),
        utterance: text,
        requestedAt,
      };
    }
    if (intent === 'research') {
      const researchPayload: Record<string, unknown> = {
        query: clampText(
          getString(payload.query) ?? getString(payload.topic) ?? extractResearchQuery(text),
          MAX_DESCRIPTION_CHARS,
        ),
        utterance: text,
        requestedAt,
      };
      const threadId = getString(payload.threadId);
      if (threadId) {
        researchPayload.threadId = threadId;
      }
      return researchPayload;
    }
    if (intent === 'note') {
      const content = clampText(
        getString(payload.content) ?? getString(payload.note) ?? extractNoteContent(text),
        MAX_NOTE_CONTENT_CHARS,
      );
      const tags =
        getStringArray(payload.tags)?.map((entry) => clampText(entry, MAX_NOTE_TAG_CHARS)) ?? [];
      return {
        title: clampText(
          getString(payload.title) ?? deriveNoteTitle(content),
          MAX_NOTE_TITLE_CHARS,
        ),
        content,
        tags: tags.slice(0, MAX_NOTE_TAGS),
        utterance: text,
        requestedAt,
      };
    }
    if (intent === 'note_search') {
      const query = clampText(
        getString(payload.query) ?? extractNoteSearchQuery(text),
        MAX_NOTE_CONTENT_CHARS,
      );
      const sinceDaysFromPayload =
        typeof payload.sinceDays === 'number' && Number.isFinite(payload.sinceDays)
          ? Math.max(1, Math.trunc(payload.sinceDays))
          : null;
      return {
        query,
        sinceDays: sinceDaysFromPayload ?? extractSinceDaysFromText(text) ?? 30,
        limit: 3,
        utterance: text,
        requestedAt,
      };
    }
    if (intent === 'briefing') {
      return {
        requestedAt,
        utterance: text,
        timeframe: clampText(getString(payload.timeframe) ?? 'today', 40),
      };
    }
    if (intent === 'email_summarize') {
      const account = getString(payload.account) ?? getString(payload.label);
      return {
        ...(account && { account: clampText(account, 80) }),
        limit:
          typeof payload.limit === 'number' && Number.isFinite(payload.limit)
            ? Math.max(1, Math.min(25, Math.trunc(payload.limit)))
            : 10,
        utterance: text,
        requestedAt,
      };
    }
    if (intent === 'health_log') {
      const metric =
        getString(payload.metric)?.toLowerCase().replace(/\s+/g, '_') ??
        extractHealthMetricFromText(text) ??
        undefined;
      const value = getNumber(payload.value);
      return {
        metric,
        value,
        unit: getString(payload.unit)?.toLowerCase().replace(/\s+/g, '_') ?? undefined,
        note: getString(payload.note) ?? undefined,
        utterance: text,
        requestedAt,
      };
    }
    if (intent === 'health_query') {
      const metric =
        getString(payload.metric)?.toLowerCase().replace(/\s+/g, '_') ??
        extractHealthMetricFromText(text) ??
        undefined;
      const sinceDaysFromPayload =
        typeof payload.period === 'number' && Number.isFinite(payload.period)
          ? Math.max(1, Math.trunc(payload.period))
          : null;
      return {
        metric,
        period: sinceDaysFromPayload ?? extractHealthQueryPeriodFromText(text) ?? 7,
        utterance: text,
        requestedAt,
      };
    }
    return {
      topic: clampText(getString(payload.topic) ?? getString(payload.query) ?? 'top', 80),
      query: clampText(getString(payload.query) ?? text, MAX_DESCRIPTION_CHARS),
      utterance: text,
      requestedAt,
    };
  }

  private async handleCalendarIntent(
    text: string,
    payload: Record<string, unknown>,
  ): Promise<IntentOutcome> {
    const now = this.now();
    const start = parseDateTime(payload.start) ?? new Date(now.getTime() + 60 * 60 * 1000);
    const requestedEnd = parseDateTime(payload.end);
    const end =
      requestedEnd && requestedEnd.getTime() > start.getTime()
        ? requestedEnd
        : new Date(start.getTime() + 60 * 60 * 1000);
    const title =
      clampText(
        getString(payload.title) ?? getString(payload.name) ?? sentenceCase(text),
        MAX_CALENDAR_TITLE_CHARS,
      ) || 'Calendar event';
    const calendarPayload: Record<string, unknown> = {
      id: getString(payload.id) ?? randomUUID(),
      title,
      start: start.toISOString(),
      end: end.toISOString(),
      status: normalizeCalendarStatus(payload.status),
      requestedAt: now.toISOString(),
      utterance: text,
    };
    const attendees = getStringArray(payload.attendees)?.map((item) =>
      clampText(item, MAX_ATTENDEE_CHARS),
    );
    if (attendees) {
      calendarPayload.attendees = attendees;
    }
    const location = getString(payload.location);
    if (location) {
      calendarPayload.location = clampText(location, MAX_LOCATION_CHARS);
    }

    await this.publishSafe(Topics.lifeos.voiceIntentCalendarAdd, calendarPayload);
    await this.publishSafe(Topics.agent.workRequested, {
      utterance: text,
      intent: 'calendar',
      payload: calendarPayload,
      requestedAt: now.toISOString(),
      origin: 'voice-core',
    });
    const responseText = `Added "${title}" to your calendar.`;
    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'agent_work_requested',
      text,
      responseText,
      intent: 'calendar',
    });
    return {
      handled: true,
      action: 'agent_work_requested',
      responseText,
    };
  }

  private async handleUnknownIntent(text: string): Promise<IntentOutcome> {
    await this.publishSafe(Topics.lifeos.voiceCommandUnhandled, {
      text,
    });

    return {
      handled: false,
      action: 'unhandled',
      responseText: 'I heard you, but I do not know how to do that yet.',
    };
  }

  private async handleTaskIntent(
    text: string,
    taskTitle: string,
    dueDate?: string | null,
  ): Promise<IntentOutcome> {
    const createdAt = this.now().toISOString();
    const planId = `goal_${randomUUID()}`;
    const taskId = `task_${randomUUID()}`;
    const planTitle = `Voice task: ${clampText(taskTitle, MAX_TASK_TITLE_CHARS) || 'Untitled task'}`;
    const trimmedCommand = clampText(text, MAX_DESCRIPTION_CHARS);

    const task: Record<string, unknown> = {
      id: taskId,
      title: clampText(taskTitle, MAX_TASK_TITLE_CHARS) || 'Untitled task',
      status: 'todo',
      priority: 4,
      voiceTriggered: true,
    };
    if (dueDate) {
      task.dueDate = dueDate;
    }

    await this.client.createNode('plan', {
      id: planId,
      createdAt,
      title: planTitle,
      description: `Created from voice command: "${trimmedCommand}"`,
      tasks: [task],
    });

    await this.publishSafe(Topics.plan.created, {
      planId,
      title: planTitle,
      createdAt,
      origin: 'voice',
    });
    await this.publishSafe(Topics.task.scheduled, {
      taskId,
      planId,
      title: taskTitle,
      scheduledAt: createdAt,
      origin: 'voice',
    });
    await this.publishSafe(Topics.lifeos.voiceCommandProcessed, {
      action: 'task_added',
      text,
      planId,
      taskId,
    });
    await this.publishSafe(Topics.lifeos.voiceIntentTaskAdd, {
      utterance: text,
      taskTitle,
      planId,
      taskId,
      requestedAt: createdAt,
      ...(dueDate ? { dueDate } : {}),
    });

    return {
      handled: true,
      action: 'task_added',
      responseText: `Added a task to ${taskTitle}.`,
      planId,
      taskId,
    };
  }

  private async publishSafe(topic: string, data: Record<string, unknown>): Promise<void> {
    try {
      await this.publish(topic, data, 'voice-core');
    } catch (error: unknown) {
      this.logger(`[voice.router] publish failed topic=${topic}: ${normalizeErrorMessage(error)}`);
    }
  }
}

