import { pcm16ToWav, type AudioTranscriptionAdapter } from './stt';

const DEFAULT_WHISPER_TIMEOUT_MS = 8_000;
const DEFAULT_SAMPLE_RATE = 16_000;
const DEFAULT_CHANNELS = 1;

export type WhisperHealthStatus = 'healthy' | 'degraded' | 'unavailable';

export interface WhisperHealthSnapshot {
  status: WhisperHealthStatus;
  configured: boolean;
  checkedAt: string;
  reason?: string;
  latencyMs?: number;
}

export interface WhisperSttAdapterOptions {
  endpoint?: string;
  timeoutMs?: number;
  sampleRate?: number;
  channels?: number;
  fetchImpl?: typeof fetch;
  now?: () => Date;
}

type WhisperTranscriptionResponse = {
  text?: unknown;
};

type WhisperHealthResponse = {
  status?: unknown;
  reason?: unknown;
};

function toOptionalString(value: unknown): string | undefined {
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
}

export class WhisperUnavailableError extends Error {
  constructor(message = 'Whisper STT runtime is not configured or unavailable.') {
    super(message);
    this.name = 'WhisperUnavailableError';
  }
}

export class WhisperSttAdapter implements AudioTranscriptionAdapter {
  private readonly endpoint: string;
  private readonly timeoutMs: number;
  private readonly sampleRate: number;
  private readonly channels: number;
  private readonly fetchImpl: typeof fetch;
  private readonly now: () => Date;

  constructor(options: WhisperSttAdapterOptions = {}) {
    this.endpoint = options.endpoint?.trim() || process.env.LIFEOS_WHISPER_ENDPOINT?.trim() || '';
    this.timeoutMs =
      options.timeoutMs ??
      Number(process.env.LIFEOS_WHISPER_TIMEOUT_MS || DEFAULT_WHISPER_TIMEOUT_MS);
    this.sampleRate = options.sampleRate ?? DEFAULT_SAMPLE_RATE;
    this.channels = options.channels ?? DEFAULT_CHANNELS;
    this.fetchImpl = options.fetchImpl ?? fetch;
    this.now = options.now ?? (() => new Date());
  }

  isConfigured(): boolean {
    return this.endpoint.length > 0;
  }

  async transcribe(audioBuffer: Buffer): Promise<string> {
    if (!this.isConfigured()) {
      throw new WhisperUnavailableError();
    }

    if (audioBuffer.length === 0) {
      return '';
    }

    const waveBuffer = pcm16ToWav(audioBuffer, this.sampleRate, this.channels);
    const response = await this.request(this.endpoint, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        audioBase64: waveBuffer.toString('base64'),
        mimeType: 'audio/wav',
        sampleRate: this.sampleRate,
        channels: this.channels,
      }),
    });

    const payload = (await response.json()) as WhisperTranscriptionResponse;
    if (typeof payload.text !== 'string') {
      throw new WhisperUnavailableError('Whisper endpoint returned an invalid transcript payload.');
    }

    return payload.text.trim();
  }

  async checkHealth(): Promise<WhisperHealthSnapshot> {
    const checkedAt = this.now().toISOString();
    if (!this.isConfigured()) {
      return {
        status: 'unavailable',
        configured: false,
        checkedAt,
        reason: 'whisper endpoint is not configured',
      };
    }

    const startedAt = Date.now();
    try {
      const response = await this.request(this.endpoint, { method: 'GET' });
      const payload = (await response.json()) as WhisperHealthResponse;
      const status = payload.status;
      const latencyMs = Date.now() - startedAt;

      if (status === 'healthy' || status === 'degraded' || status === 'unavailable') {
        return {
          status,
          configured: true,
          checkedAt,
          reason: toOptionalString(payload.reason),
          latencyMs,
        };
      }

      return {
        status: 'healthy',
        configured: true,
        checkedAt,
        latencyMs,
      };
    } catch (error) {
      return {
        status: 'degraded',
        configured: true,
        checkedAt,
        reason: error instanceof Error ? error.message : 'whisper health probe failed',
      };
    }
  }

  private async request(url: string, init: RequestInit): Promise<Response> {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), this.timeoutMs);

    try {
      const response = await this.fetchImpl(url, {
        ...init,
        signal: controller.signal,
      });

      if (!response.ok) {
        throw new WhisperUnavailableError(
          `Whisper endpoint request failed with status ${response.status}.`,
        );
      }

      return response;
    } catch (error) {
      if (error instanceof Error && error.name === 'AbortError') {
        throw new WhisperUnavailableError(
          `Whisper endpoint request timed out after ${this.timeoutMs}ms.`,
        );
      }

      if (error instanceof WhisperUnavailableError) {
        throw error;
      }

      throw new WhisperUnavailableError(
        error instanceof Error ? error.message : 'whisper endpoint request failed',
      );
    } finally {
      clearTimeout(timeout);
    }
  }
}

import { spawn } from 'node:child_process';

function toPowerShellEncodedCommand(script: string): string {
  return Buffer.from(script, 'utf16le').toString('base64');
}

function buildSpeakScript(text: string): string {
  const encodedText = Buffer.from(text, 'utf8').toString('base64');
  return `
$ErrorActionPreference = 'Stop'
Add-Type -AssemblyName System.Speech
$text = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String('${encodedText}'))
$synth = New-Object System.Speech.Synthesis.SpeechSynthesizer
try {
  $synth.Speak($text)
} finally {
  $synth.Dispose()
}
`;
}

export interface SpeechSynthesisAdapter {
  speak(text: string): Promise<void>;
}

export interface PowerShellSpeechSynthesisAdapterOptions {
  powershellPath?: string;
  timeoutMs?: number;
  logger?: (message: string) => void;
}

export class PowerShellSpeechSynthesisAdapter implements SpeechSynthesisAdapter {
  private readonly powershellPath: string;
  private readonly timeoutMs: number;
  private readonly logger: (message: string) => void;

  constructor(options: PowerShellSpeechSynthesisAdapterOptions = {}) {
    this.powershellPath = options.powershellPath ?? 'powershell.exe';
    this.timeoutMs = options.timeoutMs ?? 15_000;
    this.logger = options.logger ?? (() => undefined);
  }

  async speak(text: string): Promise<void> {
    if (!text.trim() || process.platform !== 'win32') {
      return;
    }

    const encodedScript = toPowerShellEncodedCommand(buildSpeakScript(text));
    await new Promise<void>((resolve, reject) => {
      const child = spawn(
        this.powershellPath,
        [
          '-NoProfile',
          '-NonInteractive',
          '-ExecutionPolicy',
          'Bypass',
          '-EncodedCommand',
          encodedScript,
        ],
        {
          stdio: ['ignore', 'ignore', 'pipe'],
        },
      );

      let stderr = '';
      let settled = false;
      const completeResolve = (): void => {
        if (settled) {
          return;
        }
        settled = true;
        clearTimeout(timeout);
        resolve();
      };
      const completeReject = (error: Error): void => {
        if (settled) {
          return;
        }
        settled = true;
        clearTimeout(timeout);
        reject(error);
      };
      const timeout = setTimeout(() => {
        if (child.exitCode === null && child.signalCode === null) {
          child.kill();
        }
        completeReject(new Error(`Text-to-speech timed out after ${this.timeoutMs}ms.`));
      }, this.timeoutMs);

      child.stderr.setEncoding('utf8');
      child.stderr.on('data', (chunk: string) => {
        stderr += chunk;
      });
      child.once('error', (error) => {
        completeReject(error);
      });
      child.once('exit', (code) => {
        if (code === 0) {
          completeResolve();
          return;
        }

        const normalized = stderr.trim() || `Text-to-speech exited with code ${code ?? 0}.`;
        this.logger(`[voice.tts] ${normalized}`);
        completeReject(new Error(normalized));
      });
    });
  }
}

export class NullSpeechSynthesisAdapter implements SpeechSynthesisAdapter {
  async speak(text: string): Promise<void> {
    void text;
    return;
  }
}

export interface TextToSpeechOptions {
  adapter?: SpeechSynthesisAdapter;
}

export class TextToSpeech {
  private readonly adapter: SpeechSynthesisAdapter;
  private pending: Promise<void> = Promise.resolve();

  constructor(options: TextToSpeechOptions = {}) {
    this.adapter = options.adapter ?? new PowerShellSpeechSynthesisAdapter();
  }

  async speak(text: string): Promise<void> {
    const next = this.pending.catch(() => undefined).then(() => this.adapter.speak(text));
    this.pending = next.catch(() => undefined);
    await next;
  }
}

function escapeForRegex(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function normalizeWhitespace(value: string): string {
  return value.trim().replace(/\s+/g, ' ');
}

function normalizeForComparison(value: string): string {
  return normalizeWhitespace(
    value
      .toLowerCase()
      .replace(/[^\p{L}\p{N}\s]/gu, ' ')
      .replace(/\s+/g, ' '),
  );
}

function toWakePattern(phrase: string): RegExp {
  const tokens = normalizeWhitespace(phrase).split(' ').map(escapeForRegex);
  return new RegExp(`^${tokens.join('\\s+')}([\\s,.:;!?-]*)`, 'i');
}

export interface WakeWordMatch {
  kind: 'none' | 'wake_only' | 'wake_with_command';
  matchedPhrase?: string;
  command?: string;
}

export interface WakeWordDetectorOptions {
  wakePhrases?: string[];
}

export class WakeWordDetector {
  private readonly wakePhrases: string[];
  private readonly patterns: Array<{ phrase: string; pattern: RegExp }>;

  constructor(options: WakeWordDetectorOptions = {}) {
    this.wakePhrases = options.wakePhrases?.length
      ? options.wakePhrases.map((phrase) => normalizeWhitespace(phrase)).filter(Boolean)
      : ['Hey LifeOS', 'Hey Life OS'];
    this.patterns = this.wakePhrases.map((phrase) => ({
      phrase,
      pattern: toWakePattern(phrase),
    }));
  }

  detect(text: string): WakeWordMatch {
    const raw = text.trim();
    if (!raw) {
      return { kind: 'none' };
    }

    const normalized = normalizeForComparison(raw);
    for (const entry of this.patterns) {
      const normalizedPhrase = normalizeForComparison(entry.phrase);
      if (normalized === normalizedPhrase) {
        return {
          kind: 'wake_only',
          matchedPhrase: entry.phrase,
        };
      }

      const match = raw.match(entry.pattern);
      if (!match) {
        continue;
      }

      const command = raw.slice(match[0].length).trim();
      if (!command) {
        return {
          kind: 'wake_only',
          matchedPhrase: entry.phrase,
        };
      }

      return {
        kind: 'wake_with_command',
        matchedPhrase: entry.phrase,
        command,
      };
    }

    return { kind: 'none' };
  }

  getPrimaryWakePhrase(): string {
    return this.wakePhrases[0] ?? 'Hey LifeOS';
  }
}

import { randomUUID, timingSafeEqual } from 'node:crypto';

import type { FastifyInstance } from 'fastify';
import { z } from 'zod';

import {
  SurfaceCapabilitySchema,
  SurfaceKindSchema,
  SurfaceTrustLevelSchema,
  type HomeNodeSurfaceRegistered,
  type HomeStateSnapshot,
} from '@lifeos/contracts';
import type { HomeNodeGraphClient } from '@lifeos/home-node-core';

import { DisplayFeedAggregator } from './feed';

const RegisterSurfaceRequestSchema = z
  .object({
    surface_id: z.string().min(1).optional(),
    zone_id: z.string().min(1),
    home_id: z.string().min(1),
    kind: SurfaceKindSchema,
    trust_level: SurfaceTrustLevelSchema,
    capabilities: z.array(SurfaceCapabilitySchema),
    registered_at: z.string().datetime().optional(),
    last_seen_at: z.string().datetime().optional(),
  })
  .strict();

const CreateHomeRequestSchema = z
  .object({
    home_id: z.string().min(1),
    household_id: z.string().min(1),
    name: z.string().min(1),
    timezone: z.string().min(1),
    quiet_hours_start: z.string().optional(),
    quiet_hours_end: z.string().optional(),
    routine_profile: z.string().optional(),
  })
  .strict();

const CreateZoneRequestSchema = z
  .object({
    zone_id: z.string().min(1),
    home_id: z.string().min(1),
    name: z.string().min(1),
    type: z.enum(['kitchen', 'hallway', 'bedroom', 'office', 'entryway', 'living_room', 'other']),
  })
  .strict();

const SURFACE_SECRET_HEADER = 'x-lifeos-surface-secret';

const displayFeedAggregator = new DisplayFeedAggregator();

function defaultSnapshot(now: string): HomeStateSnapshot {
  return {
    home_mode: 'home',
    occupancy_summary: 'unknown',
    active_routines: [],
    adapter_health: 'healthy',
    snapshot_at: now,
  };
}

export interface HomeNodeRouteHooks {
  onSurfaceRegistered?: (surface: HomeNodeSurfaceRegistered) => Promise<void>;
  onSurfaceDeregistered?: (surface: HomeNodeSurfaceRegistered) => Promise<void>;
  getDisplayFeedSignalVersion?: (householdId: string) => number;
  waitForDisplayFeedSignal?: (
    householdId: string,
    since: number,
    timeoutMs: number,
  ) => Promise<number>;
}

function parseBooleanFilter(value: unknown): boolean | undefined {
  if (value === undefined || value === null || value === '') {
    return undefined;
  }

  const normalized = String(value).trim().toLowerCase();
  if (normalized === 'true' || normalized === '1') {
    return true;
  }

  if (normalized === 'false' || normalized === '0') {
    return false;
  }

  return undefined;
}

function validateRouteSecret(expectedSecret: string, providedSecret: string | null | undefined): boolean {
  if (!providedSecret) {
    return false;
  }

  const expectedBuffer = Buffer.from(expectedSecret.trim(), 'utf8');
  const providedBuffer = Buffer.from(providedSecret.trim(), 'utf8');
  if (expectedBuffer.length === 0 || expectedBuffer.length !== providedBuffer.length) {
    return false;
  }

  return timingSafeEqual(expectedBuffer, providedBuffer);
}

function readHeaderValue(value: string | string[] | undefined): string | undefined {
  if (!value) {
    return undefined;
  }

  if (Array.isArray(value)) {
    return value[0];
  }

  return value;
}

function isAuthorizedSurfaceMutation(
  expectedSecret: string,
  request: { headers?: Record<string, string | string[] | undefined>; body?: unknown },
): boolean {
  const providedFromHeader = readHeaderValue(request.headers?.[SURFACE_SECRET_HEADER]);
  const providedFromBody =
    typeof (request.body as { surface_secret?: unknown } | undefined)?.surface_secret === 'string'
      ? (request.body as { surface_secret?: string }).surface_secret
      : undefined;

  return validateRouteSecret(expectedSecret, providedFromHeader ?? providedFromBody ?? null);
}

export function registerHomeNodeRoutes(
  app: FastifyInstance,
  graphClient: HomeNodeGraphClient,
  hooks: HomeNodeRouteHooks = {},
): void {
  const expectedSurfaceSecret = process.env.LIFEOS_HOME_NODE_SURFACE_SECRET ?? '';

  app.post('/api/home-node/homes', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    try {
      const payload = CreateHomeRequestSchema.parse(request.body ?? {});
      const home = graphClient.upsertHome({
        homeId: payload.home_id,
        householdId: payload.household_id,
        name: payload.name,
        timezone: payload.timezone,
        quietHoursStart: payload.quiet_hours_start,
        quietHoursEnd: payload.quiet_hours_end,
        routineProfile: payload.routine_profile,
      });

      return reply.code(201).send(home);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return reply.code(400).send({ error: 'Invalid home payload' });
      }

      return reply.code(500).send({ error: 'Failed to create home' });
    }
  });

  app.post('/api/home-node/zones', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    try {
      const payload = CreateZoneRequestSchema.parse(request.body ?? {});
      if (!graphClient.getHomeById(payload.home_id)) {
        return reply.code(404).send({ error: `home ${payload.home_id} was not found` });
      }

      const zone = graphClient.upsertZone({
        zoneId: payload.zone_id,
        homeId: payload.home_id,
        name: payload.name,
        type: payload.type,
      });

      return reply.code(201).send(zone);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return reply.code(400).send({ error: 'Invalid zone payload' });
      }

      return reply.code(500).send({ error: 'Failed to create zone' });
    }
  });

  app.get('/api/home-node/snapshot/:householdId', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    const householdId = String((request.params as { householdId?: string }).householdId ?? '').trim();
    if (householdId.length === 0) {
      return reply.code(400).send({ error: 'householdId is required' });
    }

    const snapshot = graphClient.getHomeStateSnapshot(householdId);
    if (!snapshot) {
      return reply.code(404).send({ error: 'Snapshot not found' });
    }

    return reply.code(200).send(snapshot);
  });

  const getFeedHandler = async (
    request: Parameters<FastifyInstance['get']>[1] extends (...args: infer A) => unknown ? A[0] : never,
    reply: Parameters<FastifyInstance['get']>[1] extends (...args: infer A) => unknown ? A[1] : never,
  ) => {
    try {
      if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
        return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
      }

      const surfaceId = String((request.params as { surfaceId?: string }).surfaceId ?? '').trim();
      if (surfaceId.length === 0) {
        return reply.code(400).send({ error: 'surfaceId is required' });
      }

      const registeredSurface = graphClient.getRegisteredSurface(surfaceId);
      const surfaceState = graphClient.getSurface(surfaceId);
      if (!registeredSurface || !surfaceState || !surfaceState.active) {
        return reply.code(404).send({ error: 'Surface not found' });
      }

      const home = graphClient.getHomeById(registeredSurface.home_id);
      if (!home) {
        return reply.code(404).send({ error: 'Home not found' });
      }

      const snapshot =
        graphClient.getHomeStateSnapshot(registeredSurface.household_id) ??
        defaultSnapshot(new Date().toISOString());

      const { feed } = await displayFeedAggregator.getDisplayFeed({
        surface: registeredSurface,
        home,
        snapshot,
      });

      return reply.code(200).send(feed);
    } catch {
      return reply.code(500).send({ error: 'Failed to build display feed' });
    }
  };

  app.get('/api/home-node/display-feed/:surfaceId', getFeedHandler);

  app.get('/api/home-node/display-feed-hints/:surfaceId', async (request, reply) => {
    try {
      if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
        return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
      }

      const surfaceId = String((request.params as { surfaceId?: string }).surfaceId ?? '').trim();
      if (surfaceId.length === 0) {
        return reply.code(400).send({ error: 'surfaceId is required' });
      }

      const registeredSurface = graphClient.getRegisteredSurface(surfaceId);
      const surfaceState = graphClient.getSurface(surfaceId);
      if (!registeredSurface || !surfaceState || !surfaceState.active) {
        return reply.code(404).send({ error: 'Surface not found' });
      }

      const query = request.query as {
        householdId?: string;
        since?: string;
        timeoutMs?: string;
      };
      const householdId = query.householdId?.trim() || registeredSurface.household_id;
      if (householdId !== registeredSurface.household_id) {
        return reply.code(403).send({ error: 'Surface does not belong to household' });
      }

      const since = Number.parseInt(String(query.since ?? '0'), 10);
      const timeoutMs = Math.min(
        Math.max(Number.parseInt(String(query.timeoutMs ?? '30000'), 10), 0),
        60_000,
      );

      const currentVersion = hooks.getDisplayFeedSignalVersion?.(householdId) ?? 0;
      const signalVersion =
        hooks.waitForDisplayFeedSignal && currentVersion <= since
          ? await hooks.waitForDisplayFeedSignal(householdId, since, timeoutMs)
          : currentVersion;

      return reply.code(200).send({ signalVersion });
    } catch {
      return reply.code(500).send({ error: 'Failed to fetch display-feed hints' });
    }
  });

  const registerSurfaceHandler = async (
    request: Parameters<FastifyInstance['post']>[1] extends (...args: infer A) => unknown ? A[0] : never,
    reply: Parameters<FastifyInstance['post']>[1] extends (...args: infer A) => unknown ? A[1] : never,
  ) => {
    try {
      if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
        return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
      }

      const payload = RegisterSurfaceRequestSchema.parse(request.body ?? {});
      const surface = graphClient.registerSurface({
        surfaceId: payload.surface_id ?? randomUUID(),
        zoneId: payload.zone_id,
        homeId: payload.home_id,
        kind: payload.kind,
        trustLevel: payload.trust_level,
        capabilities: payload.capabilities,
        registeredAt: payload.registered_at,
        lastSeenAt: payload.last_seen_at,
      });

      await hooks.onSurfaceRegistered?.(surface);
      return reply.code(201).send(surface);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return reply.code(400).send({ error: 'Invalid surface registration payload' });
      }

      if (error instanceof Error) {
        if (error.message.includes('was not found')) {
          return reply.code(404).send({ error: error.message });
        }

        if (
          error.message.includes('does not belong to home') ||
          error.message.includes('trust level is immutable once registered')
        ) {
          return reply.code(409).send({ error: error.message });
        }
      }

      return reply.code(500).send({ error: 'Failed to register surface' });
    }
  };

  app.post('/api/home-node/surfaces/register', registerSurfaceHandler);
  app.post('/api/home-node/surfaces', registerSurfaceHandler);

  app.delete('/api/home-node/surfaces/:surfaceId', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    const surfaceId = String((request.params as { surfaceId?: string }).surfaceId ?? '').trim();
    if (surfaceId.length === 0) {
      return reply.code(400).send({ error: 'surfaceId is required' });
    }

    const surface = graphClient.deregisterSurface(surfaceId);
    if (!surface) {
      return reply.code(404).send({ error: 'Surface not found' });
    }

    await hooks.onSurfaceDeregistered?.(surface);
    return reply.code(200).send({ surface_id: surfaceId, status: 'deregistered' });
  });

  app.get('/api/home-node/surfaces', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    const query = request.query as {
      householdId?: string;
      homeId?: string;
      zoneId?: string;
      active?: string;
    };

    const householdId = query.householdId?.trim() ?? '';
    if (householdId.length === 0) {
      return reply.code(400).send({ error: 'householdId is required' });
    }

    const surfaces = graphClient.listSurfaces({
      householdId,
      homeId: query.homeId?.trim() || undefined,
      zoneId: query.zoneId?.trim() || undefined,
      active: parseBooleanFilter(query.active),
    });

    return reply.code(200).send({ items: surfaces, count: surfaces.length });
  });

  app.post('/api/home-node/surfaces/:surfaceId/heartbeat', async (request, reply) => {
    if (!isAuthorizedSurfaceMutation(expectedSurfaceSecret, request)) {
      return reply.code(401).send({ error: 'Unauthorized surface mutation request' });
    }

    const surfaceId = String((request.params as { surfaceId?: string }).surfaceId ?? '').trim();
    if (surfaceId.length === 0) {
      return reply.code(400).send({ error: 'surfaceId is required' });
    }

    const heartbeatAt =
      typeof (request.body as { seen_at?: unknown } | undefined)?.seen_at === 'string'
        ? (request.body as { seen_at?: string }).seen_at
        : undefined;
    const surface = graphClient.recordSurfaceHeartbeat(surfaceId, heartbeatAt);
    if (!surface) {
      return reply.code(404).send({ error: 'Surface not found' });
    }

    return reply.code(200).send(surface);
  });
}

import {
  HomeNodeDisplayFeedSchema,
  type HomeNodeDisplayFeed,
  type HomeNodeHome,
  type HomeNodeSurfaceRegistered,
  type HomeStateSnapshot,
  type SurfaceTrustLevel,
} from '@lifeos/contracts';
import { createSecurityClient } from '@lifeos/security';

export const DISPLAY_FEED_CACHE_TTL_MS = 30_000;

export interface DashboardDisplayFeedData {
  todayEvents?: HomeNodeDisplayFeed['todayEvents'];
  choresDueToday?: HomeNodeDisplayFeed['choresDueToday'];
  shoppingItems?: HomeNodeDisplayFeed['shoppingItems'];
  topReminders?: HomeNodeDisplayFeed['topReminders'];
  householdNotices?: HomeNodeDisplayFeed['householdNotices'];
}

export interface BuildDisplayFeedInput {
  snapshot: HomeStateSnapshot;
  dashboardData?: DashboardDisplayFeedData;
  stale: boolean;
  generatedAt?: string;
}

export interface DisplayFeedAggregatorInput {
  surface: HomeNodeSurfaceRegistered;
  home: HomeNodeHome;
  snapshot: HomeStateSnapshot;
}

export interface DisplayFeedAggregatorResult {
  feed: HomeNodeDisplayFeed;
  fromCache: boolean;
}

export interface DashboardFetchOptions {
  authToken?: string;
}

export type DashboardFetcher = (
  url: string,
  options?: DashboardFetchOptions,
) => Promise<DashboardDisplayFeedData>;

export interface DisplayFeedAggregatorOptions {
  dashboardBaseUrl?: string;
  dashboardServiceTokenProvider?: () => Promise<string | undefined>;
}

interface CachedFeedEntry {
  expiresAtMs: number;
  feed: HomeNodeDisplayFeed;
}

export function applyContentFilter(
  feed: HomeNodeDisplayFeed,
  trustLevel: SurfaceTrustLevel,
): HomeNodeDisplayFeed {
  if (trustLevel === 'personal') {
    return HomeNodeDisplayFeedSchema.parse(feed);
  }

  const withoutSensitiveReminders = feed.topReminders.filter((reminder) => !reminder.sensitive);

  if (trustLevel === 'guest') {
    return HomeNodeDisplayFeedSchema.parse({
      ...feed,
      todayEvents: [],
      choresDueToday: [],
      topReminders: [],
      householdNotices: feed.householdNotices.filter((notice) => notice.severity !== 'warning'),
      shoppingItems: feed.shoppingItems,
    });
  }

  return HomeNodeDisplayFeedSchema.parse({
    ...feed,
    topReminders: withoutSensitiveReminders,
  });
}

function resolveEffectiveTrustLevel(
  surfaceTrustLevel: SurfaceTrustLevel,
  homeMode: HomeStateSnapshot['home_mode'],
): SurfaceTrustLevel {
  if (homeMode === 'guest_mode') {
    return 'guest';
  }

  return surfaceTrustLevel;
}

function buildNotices(snapshot: HomeStateSnapshot): HomeNodeDisplayFeed['householdNotices'] {
  const notices: HomeNodeDisplayFeed['householdNotices'] = [];

  if (snapshot.home_mode === 'quiet_hours') {
    notices.push({
      id: 'quiet-hours',
      title: 'Quiet hours active',
      message: 'Display is in reduced ambient mode.',
      severity: 'info',
    });
  }

  if (snapshot.home_mode === 'guest_mode') {
    notices.push({
      id: 'guest-mode',
      title: 'Guest mode active',
      message: 'Sensitive household content is hidden.',
      severity: 'warning',
    });
  }

  if (snapshot.adapter_health !== 'healthy') {
    notices.push({
      id: 'adapter-health',
      title: 'Home adapter degraded',
      message: `Adapter status is ${snapshot.adapter_health}.`,
      severity: 'warning',
    });
  }

  return notices;
}

export function buildDisplayFeed(input: BuildDisplayFeedInput): HomeNodeDisplayFeed {
  const generatedAt = input.generatedAt ?? new Date().toISOString();
  const dashboardData = input.dashboardData ?? {};

  return HomeNodeDisplayFeedSchema.parse({
    todayEvents: dashboardData.todayEvents ?? [],
    choresDueToday: dashboardData.choresDueToday ?? [],
    shoppingItems: dashboardData.shoppingItems ?? [],
    topReminders: dashboardData.topReminders ?? [],
    householdNotices:
      (dashboardData.householdNotices?.length ?? 0) > 0
        ? dashboardData.householdNotices
        : buildNotices(input.snapshot),
    stale: input.stale,
    generatedAt,
  });
}

async function fetchDashboardDataWithAuth(
  url: string,
  options: DashboardFetchOptions = {},
): Promise<DashboardDisplayFeedData> {
  const requestInit: RequestInit = {
    signal: AbortSignal.timeout(2_000),
  };
  if (options.authToken) {
    requestInit.headers = { Authorization: `Bearer ${options.authToken}` };
  }

  const response = await fetch(url, requestInit);
  if (!response.ok) {
    throw new Error(`dashboard display feed request failed: ${response.status}`);
  }

  const payload = (await response.json()) as DashboardDisplayFeedData;
  return payload;
}

function createDashboardServiceTokenProvider(): () => Promise<string | undefined> {
  const securityClient = createSecurityClient();
  let cachedToken: { token: string; expiresAtMs: number } | null = null;

  return async () => {
    const nowMs = Date.now();
    if (cachedToken && cachedToken.expiresAtMs > nowMs + 5_000) {
      return cachedToken.token;
    }

    const issued = await securityClient.issueServiceToken('home-node');
    const expiresAtMs = new Date(issued.expiresAt).getTime();
    cachedToken = {
      token: issued.token,
      expiresAtMs: Number.isFinite(expiresAtMs) ? expiresAtMs : nowMs + 60_000,
    };

    return cachedToken.token;
  };
}

function normalizeDashboardBaseUrl(raw: string | undefined): string {
  const normalized = (raw ?? '').trim();
  if (!normalized) {
    return 'http://localhost:3000';
  }

  return normalized.replace(/\/+$/, '');
}

export class DisplayFeedAggregator {
  private readonly cache = new Map<string, CachedFeedEntry>();
  private readonly dashboardBaseUrl: string;
  private readonly dashboardServiceTokenProvider: () => Promise<string | undefined>;

  constructor(
    private readonly dashboardFetcher: DashboardFetcher = fetchDashboardDataWithAuth,
    private readonly now: () => number = () => Date.now(),
    options: DisplayFeedAggregatorOptions = {},
  ) {
    this.dashboardBaseUrl = normalizeDashboardBaseUrl(
      options.dashboardBaseUrl ?? process.env.LIFEOS_DASHBOARD_BASE_URL,
    );
    this.dashboardServiceTokenProvider =
      options.dashboardServiceTokenProvider ?? createDashboardServiceTokenProvider();
  }

  private getFromCache(surfaceId: string): CachedFeedEntry | undefined {
    return this.cache.get(surfaceId);
  }

  async getDisplayFeed(input: DisplayFeedAggregatorInput): Promise<DisplayFeedAggregatorResult> {
    const effectiveTrustLevel = resolveEffectiveTrustLevel(
      input.surface.trust_level,
      input.snapshot.home_mode,
    );
    const cached = this.getFromCache(input.surface.surface_id);
    const nowMs = this.now();

    if (cached && cached.expiresAtMs > nowMs) {
      const freshFromCache = HomeNodeDisplayFeedSchema.parse({
        ...cached.feed,
        stale: false,
        generatedAt: new Date(nowMs).toISOString(),
      });
      return { feed: applyContentFilter(freshFromCache, effectiveTrustLevel), fromCache: true };
    }

    try {
      const dashboardServiceToken = await this.dashboardServiceTokenProvider();
      const fetchOptions = dashboardServiceToken
        ? { authToken: dashboardServiceToken }
        : undefined;
      const dashboardData = await this.dashboardFetcher(
        `${this.dashboardBaseUrl}/api/households/${input.surface.household_id}/display-feed`,
        fetchOptions,
      );
      const feed = buildDisplayFeed({
        snapshot: input.snapshot,
        dashboardData,
        stale: false,
        generatedAt: new Date(nowMs).toISOString(),
      });
      this.cache.set(input.surface.surface_id, {
        feed,
        expiresAtMs: nowMs + DISPLAY_FEED_CACHE_TTL_MS,
      });

      return {
        feed: applyContentFilter(feed, effectiveTrustLevel),
        fromCache: false,
      };
    } catch {
      if (cached) {
        const staleCached = HomeNodeDisplayFeedSchema.parse({
          ...cached.feed,
          stale: true,
          generatedAt: new Date(nowMs).toISOString(),
        });
        return {
          feed: applyContentFilter(staleCached, effectiveTrustLevel),
          fromCache: true,
        };
      }

      const staleSnapshotOnly = buildDisplayFeed({
        snapshot: input.snapshot,
        dashboardData: {
          householdNotices: buildNotices(input.snapshot),
        },
        stale: true,
        generatedAt: new Date(nowMs).toISOString(),
      });

      return {
        feed: applyContentFilter(staleSnapshotOnly, effectiveTrustLevel),
        fromCache: false,
      };
    }
  }
}
